const QUESTIONS_ECIH_C5 = [
  { id:80901, domain:5, level:1, question:"Under the cloud shared responsibility model, who is responsible for securing the underlying physical hypervisor hosts?", options:["The cloud service provider retains responsibility for the physical hosts and hypervisor layer at all times","The customer must patch and secure the hypervisor hosts across every cloud service model offered within the affected environment","Responsibility for the hypervisor is always split evenly between the provider and the customer","A third-party auditor assumes responsibility for hypervisor security in most cloud service contracts"], correct:0, explanation:"The provider owns physical and virtualization layers; the customer never patches the hypervisor, so the other options are wrong." },
  { id:80902, domain:5, level:2, question:"In an IaaS deployment, which security task remains the customer's responsibility during incident handling?", options:["Maintaining the physical security of the provider's regional data centers, racks, and cabling systems","Securing the guest operating system, applications, and data running on provisioned compute instances","Patching the hypervisor kernel that hosts all of the tenant virtual machines in the region","Securing the provider's global network backbone that links the availability zones together"], correct:1, explanation:"In IaaS the customer owns the OS upward; physical, hypervisor, and backbone belong to the provider, so those are wrong." },
  { id:80903, domain:5, level:3, question:"For a SaaS application, what does the customer typically remain responsible for from a security standpoint?", options:["Patching the application source code and the underlying language runtime that the vendor operates within the affected environment","Hardening the operating system and middleware components that host the SaaS platform servers","User access management, data classification, and appropriate configuration of the provided application settings","Managing the physical infrastructure and internal network of the SaaS provider's data centers"], correct:2, explanation:"In SaaS the vendor runs the stack; the customer keeps identity, data, and config duties, so infrastructure and code options are wrong." },
  { id:80904, domain:5, level:2, question:"Why does the shared responsibility model complicate cloud incident response for handlers?", options:["It removes any need for the customer to keep independent logs of their own account activity within the affected environment","It gives the customer full physical access to seize the provider's hardware during any incident","It transfers all legal liability for data breaches entirely onto the cloud service provider","Evidence and control boundaries are split between provider and customer, requiring coordination for access"], correct:3, explanation:"Split ownership forces provider coordination for some evidence; customers still keep logs and rarely get hardware, so those are wrong." },
  { id:80905, domain:5, level:3, question:"A PaaS customer suffers a code injection incident. Which layer is the customer accountable for securing?", options:["The application code and the data they deploy onto the provider's managed platform runtime","The operating system and language runtime patching, which the provider manages under PaaS within the affected environment","The load balancers and network fabric that are operated entirely by the cloud provider","The physical servers and storage arrays hosting the platform-as-a-service environment"], correct:0, explanation:"In PaaS the provider manages OS, runtime, and network; the customer owns their code and data, so the other options are wrong." },
  { id:80906, domain:5, level:1, question:"Which statement best describes the shared responsibility boundary as workloads move from IaaS toward SaaS?", options:["Customer responsibility increases for physical hardware as the workload moves toward SaaS models within the affected environment","Customer responsibility steadily decreases while provider responsibility increases across the stack layers","Provider responsibility disappears entirely once a workload is delivered as software as a service","Responsibility is identical across IaaS, PaaS, and SaaS because the boundary never actually shifts"], correct:1, explanation:"Moving toward SaaS shifts more duties to the provider; the boundary does shift and hardware is never the customer's, so those are wrong." },
  { id:80907, domain:5, level:2, question:"A customer assumes the provider is scanning their SaaS-stored files for malware, but the contract says otherwise. What went wrong?", options:["The provider secretly disabled all malware scanning in order to reduce their own operating costs within the affected environment","The SaaS model legally requires the provider to scan every single customer file for malware","A misunderstanding of the shared responsibility model left a data-protection gap unaddressed by the customer","Malware scanning is technically impossible in any SaaS environment due to encryption at rest"], correct:2, explanation:"The gap stems from misreading responsibilities; the provider is not legally bound to scan and scanning is feasible, so those are wrong." },
  { id:80908, domain:5, level:2, question:"Which AWS service records API calls and management-plane activity essential for cloud incident investigation?", options:["AWS CloudFront, which caches and distributes static web content to globally located edge servers","AWS CloudFormation, which provisions cloud infrastructure from declarative stack templates only","AWS Cost Explorer, which visualizes and forecasts monthly account spending across many services","AWS CloudTrail, which logs account API activity across services for auditing and forensic review"], correct:3, explanation:"CloudTrail captures API and management events; CloudFront, CloudFormation, and Cost Explorer serve delivery, IaC, and billing, so they are wrong." },
  { id:80909, domain:5, level:2, question:"Which AWS service uses machine learning to detect threats like credential compromise and cryptomining?", options:["Amazon GuardDuty, a threat detection service analyzing CloudTrail, VPC flow, and DNS log data","Amazon Inspector, which performs only static vulnerability assessment of the running instances","AWS Shield, which is exclusively a distributed denial-of-service protection service offering","AWS Config, which records resource configuration changes to support ongoing compliance auditing"], correct:0, explanation:"GuardDuty does continuous threat detection; Inspector, Shield, and Config address vulnerabilities, DDoS, and drift, so they are wrong." },
  { id:80910, domain:5, level:1, question:"In Microsoft Azure, which service provides cloud-native SIEM and SOAR for incident detection and response?", options:["Azure Blob Storage, which provides scalable object storage for unstructured application data within the affected environment","Microsoft Sentinel, which ingests logs for analytics, threat detection, and automated response","Azure DevOps, which manages CI/CD pipelines and source repositories for engineering teams","Azure CDN, which distributes cached web content from globally located edge network nodes"], correct:1, explanation:"Sentinel is the SIEM/SOAR; Blob, DevOps, and CDN handle storage, pipelines, and delivery, so they are wrong." },
  { id:80911, domain:5, level:3, question:"Which Azure service aggregates platform metrics and activity logs used to trace resource changes during an incident?", options:["Azure Bastion, which provides only secure RDP and SSH connectivity to the virtual machines within the affected environment","Azure Key Vault, which stores and manages application secrets, keys, and certificates","Azure Monitor, which aggregates metrics, activity logs, and diagnostics across cloud resources","Azure Front Door, which is a global application delivery and load-balancing service offering"], correct:2, explanation:"Azure Monitor centralizes telemetry; Bastion, Key Vault, and Front Door handle access, secrets, and delivery, so they are wrong." },
  { id:80912, domain:5, level:2, question:"In Google Cloud, which log type records administrative actions and is enabled by default for incident review?", options:["Cloud CDN cache logs, which record only content delivery hit and miss statistics per edge node","Cloud Build logs, which capture only the console output from continuous integration build steps","BigQuery job logs, which record only analytical SQL statements executed against the datasets","Cloud Audit Logs Admin Activity logs, which capture configuration and metadata change events"], correct:3, explanation:"Admin Activity audit logs record management actions by default; CDN, Build, and BigQuery logs are narrower, so they are wrong." },
  { id:80913, domain:5, level:3, question:"A handler needs to reconstruct data-read events in GCP. Which log category must be enabled?", options:["Data Access audit logs, which record reads and writes to user-managed resource data","Admin Activity logs alone, which do not capture the routine data read operations by users","VPC firewall rules, which define allowed traffic but never log any data access events","IAM policy bindings, which describe permissions but are not themselves an event log source"], correct:0, explanation:"Data Access logs capture reads and must be explicitly enabled; Admin Activity omits reads and rules or policies are not logs, so those are wrong." },
  { id:80914, domain:5, level:2, question:"Why should cloud audit logs be exported to a separate, access-restricted account or project?", options:["To reduce the total storage cost incurred within the primary production account only","To prevent an attacker who compromises the primary account from deleting the evidence trail","To make the collected logs completely unreadable to security analysts during investigations","To remove the requirement to correlate events across multiple separate cloud accounts"], correct:1, explanation:"Isolated export protects log integrity from an attacker in the main account; it does not cut cost, hide logs, or remove correlation, so those are wrong." },
  { id:80915, domain:5, level:1, question:"Which log source best reveals that a cloud storage bucket's permissions were changed to public?", options:["Application performance metrics showing the average latency of object download requests only within the affected environment","Billing reports summarizing the monthly cost of storage and the outbound data transfer","Management-plane API logs such as CloudTrail recording the PutBucketAcl or policy change call","Instance operating-system logs recording local user login and logout activity on the host"], correct:2, explanation:"Management-plane API logs capture the ACL or policy change; performance, billing, and OS logs do not record that action, so they are wrong." },
  { id:80916, domain:5, level:3, question:"An attacker discovers a publicly readable object storage bucket exposing customer data. What is the root cause?", options:["A zero-day vulnerability in the storage service's server-side encryption implementation itself within the affected environment","A hardware failure in the provider's storage subsystem exposing the raw physical disk contents","An expired TLS certificate on the bucket endpoint disabling transport encryption entirely","A misconfigured bucket access policy granting public or overly broad read permissions to objects"], correct:3, explanation:"Public exposure is an access-policy misconfiguration; it is not a provider zero-day, hardware fault, or certificate issue, so those are wrong." },
  { id:80917, domain:5, level:2, question:"Which indicator most strongly suggests cloud account credential compromise in CloudTrail logs?", options:["API calls originating from an unfamiliar geographic region and IP address outside normal patterns","A gradual and expected increase in storage usage that aligns with steady ongoing business growth within the affected environment","Scheduled automated backups completing successfully at their normally configured daily times","Routine read-only console logins observed from the user's registered corporate office network"], correct:0, explanation:"Anomalous source geography and IP signal compromise; normal growth, successful backups, and expected logins are benign, so they are wrong." },
  { id:80918, domain:5, level:3, question:"What is cryptojacking in a cloud environment?", options:["Encrypting a victim's cloud storage buckets and demanding a ransom payment for the decryption keys","Unauthorized use of compromised cloud compute resources to mine cryptocurrency for the attacker","Intercepting encrypted cloud API traffic in transit to steal the active user session tokens","Deleting cloud volume snapshots to prevent any forensic recovery after an intrusion occurs"], correct:1, explanation:"Cryptojacking hijacks compute to mine coins; ransom encryption, token theft, and snapshot deletion are different attacks, so they are wrong." },
  { id:80919, domain:5, level:2, question:"An attacker abuses an over-permissioned IAM role to gain broader access. This is best described as what?", options:["A denial-of-service attack that deliberately exhausts the account's API request rate quota within the affected environment","A supply-chain attack that injects malicious code into a shared build and release pipeline","Cloud privilege escalation exploiting excessive IAM permissions or a misconfigured trust policy","A phishing campaign that harvests console passwords directly from unsuspecting end users"], correct:2, explanation:"Abusing IAM permissions to widen access is privilege escalation; DoS, supply chain, and phishing are unrelated vectors, so they are wrong." },
  { id:80920, domain:5, level:3, question:"Which misconfiguration commonly enables privilege escalation through an IAM policy in AWS?", options:["Enabling multi-factor authentication on every privileged administrative account in the org within the affected environment","Applying least-privilege scoped policies to each individual service principal or role carefully","Rotating access keys automatically on a strict and consistently enforced ninety-day schedule","Granting iam:PassRole or wildcard permissions that let a principal assume higher-privileged roles"], correct:3, explanation:"Broad PassRole or wildcard grants enable escalation; MFA, least privilege, and key rotation are protective, so they are wrong." },
  { id:80921, domain:5, level:1, question:"An insecure cloud API lacking authentication is exploited. Which control would have most directly prevented this?", options:["Enforcing strong authentication and authorization on every externally exposed API endpoint","Increasing the compute instance size of the servers hosting the API backend service greatly","Adding additional caching layers in front of the API to improve its typical response times","Compressing the API response payloads to reduce the outbound bandwidth costs being incurred"], correct:0, explanation:"Authentication and authorization on endpoints prevent unauthenticated abuse; scaling, caching, and compression are performance measures, so they are wrong." },
  { id:80922, domain:5, level:2, question:"What container-related attack involves escaping the container to access the underlying host?", options:["A DNS cache poisoning attack that redirects the container's outbound name lookup queries","A container breakout exploiting a runtime or kernel flaw to reach the host operating system","A brute-force attack conducted against the container registry's administrative web portal","A cross-site scripting flaw located in the container orchestrator's web dashboard interface"], correct:1, explanation:"Container breakout escapes to the host via runtime or kernel flaws; DNS poisoning, registry brute force, and XSS differ, so they are wrong." },
  { id:80923, domain:5, level:3, question:"In Kubernetes, exposing which component without authentication most directly enables full cluster compromise?", options:["A single application pod's readiness probe endpoint that only returns a basic health status","The cluster's metrics port exposing aggregate CPU and memory counters to the network","The Kubernetes API server or an unsecured kubelet allowing unauthenticated cluster control","A ConfigMap object containing only non-sensitive application feature-flag default values"], correct:2, explanation:"An open API server or kubelet grants cluster control; a probe, metrics port, or benign ConfigMap do not, so those are wrong." },
  { id:80924, domain:5, level:2, question:"An attacker steals a long-lived cloud access key committed to a public code repository. Best immediate response?", options:["Increase the account's monthly spending limit to absorb any cryptomining-related costs incurred","Wait to observe whether the key is actually used before taking any remediation action at all","Make the repository private but leave the exposed access key active for service continuity","Revoke and rotate the exposed key immediately, then review all activity performed with it"], correct:3, explanation:"Revoking and rotating stops abuse; raising limits, waiting, or leaving it active keep the credential exploitable, so those are wrong." },
  { id:80925, domain:5, level:3, question:"A cloud instance suddenly shows sustained 100% CPU and outbound traffic to a mining pool. What is the likely incident?", options:["Cryptojacking, where compromised compute is used to mine cryptocurrency for an outside attacker","A legitimate autoscaling event responding to a normal spike in customer application demand within the affected environment","A scheduled backup job that briefly consumes CPU while copying volumes to object storage","A routine operating-system patch installation that temporarily raises processor utilization"], correct:0, explanation:"Sustained CPU plus mining-pool traffic indicates cryptojacking; autoscaling, backups, and patching do not target mining pools, so they are wrong." },
  { id:80926, domain:5, level:1, question:"Which cloud attack technique abuses the instance metadata service to obtain temporary credentials?", options:["A physical theft of the hard drive containing the instance's long-term access key files within the affected environment","An SSRF flaw in a hosted application used to query the metadata endpoint for role credentials","A brute-force attack against the cloud console login page that is protected by rate limiting","A phishing email tricking an administrator into revealing a static shared database password"], correct:1, explanation:"SSRF to the metadata endpoint harvests role credentials; drive theft, console brute force, and phishing use different means, so they are wrong." },
  { id:80927, domain:5, level:2, question:"An attacker gains initial access, then creates new IAM users and access keys. This activity best represents which phase?", options:["Reconnaissance, since creating identities only gathers information about the target environment","Data exfiltration, because new users automatically copy data out of the compromised account","Establishing persistence in the cloud environment so access survives credential rotation later","Denial of service, as adding users prevents legitimate administrators from logging in at all"], correct:2, explanation:"Creating hidden users and keys establishes persistence; it is not recon, exfiltration, or DoS, so those options are wrong." },
  { id:80928, domain:5, level:2, question:"Why is multi-tenancy a significant challenge in cloud forensic evidence acquisition?", options:["Multi-tenancy guarantees each investigator direct physical access to the specific host server within the affected environment","It ensures that every tenant's logs are automatically preserved indefinitely by the provider","It removes any need to coordinate the evidence acquisition requests with the cloud provider","Multiple customers share physical hardware, so acquiring one tenant's data risks exposing another's"], correct:3, explanation:"Shared hardware raises isolation and exposure concerns; multi-tenancy grants no physical access, indefinite logs, or provider-free acquisition, so those are wrong." },
  { id:80929, domain:5, level:2, question:"What is the recommended method to preserve the state of a running cloud instance for forensic analysis?", options:["Create a snapshot or image of the volume and memory before the instance is ever terminated","Immediately delete the instance to stop the attacker from causing any further harm at all within the affected environment","Reboot the instance so that the volatile logs are flushed cleanly to persistent storage","Downgrade the instance type to reduce cost while the investigation slowly proceeds later"], correct:0, explanation:"Snapshotting preserves evidence; deleting destroys it, rebooting loses volatile data, and downgrading is irrelevant, so those are wrong." },
  { id:80930, domain:5, level:1, question:"Why does data volatility complicate cloud incident forensics compared with traditional environments?", options:["Cloud data is never volatile because the providers permanently retain every byte forever within the affected environment","Ephemeral instances and autoscaling can terminate resources, destroying evidence before capture","Volatility affects only on-premises systems and never any cloud-hosted workload at all","Volatile cloud data is always encrypted and therefore can never be lost during an incident"], correct:1, explanation:"Autoscaling and ephemeral resources destroy evidence quickly; cloud data is not permanently retained, so the other options are wrong." },
  { id:80931, domain:5, level:3, question:"Which jurisdictional issue frequently arises during cross-border cloud investigations?", options:["Cloud data is exempt from all national and international data protection laws by default within the affected environment","A single global legal standard uniformly governs all cloud evidence collection worldwide","Data may reside in another country whose laws restrict access, seizure, or disclosure of it","Jurisdiction is irrelevant because providers waive every legal boundary in their contracts"], correct:2, explanation:"Cross-border data triggers conflicting national laws; there is no universal exemption, single standard, or waiver, so those are wrong." },
  { id:80932, domain:5, level:2, question:"What is a key limitation when relying on provider-supplied logs as forensic evidence?", options:["Provider logs are always inadmissible in every court under all possible circumstances ever within the affected environment","Provider logs automatically capture full disk images of every tenant on the shared platform","Provider logs are stored on the customer's own premises for direct physical seizure anytime","The customer depends on the provider's log retention, integrity, and cooperation to obtain them"], correct:3, explanation:"Reliance on provider retention and cooperation is the true limitation; provider logs are not categorically inadmissible or on-prem disk images, so those are wrong." },
  { id:80933, domain:5, level:3, question:"Before acquiring a cloud snapshot as evidence, why should the handler record its hash and metadata?", options:["To preserve integrity and establish a defensible chain of custody for the acquired image","To compress the snapshot so that it consumes far less object storage space overall later","To automatically encrypt the snapshot with the provider's default managed storage key","To speed up the copy operation by skipping any unchanged blocks during the transfer"], correct:0, explanation:"Hashing and metadata preserve integrity and chain of custody; they do not compress, encrypt, or speed copying, so those options are wrong." },
  { id:80934, domain:5, level:2, question:"Which factor makes attribution difficult in cloud incident forensics?", options:["Cloud providers publish the personal identity of every attacker in real-time public dashboards within the affected environment","Shared IP ranges, ephemeral addresses, and provider NAT can obscure the true source of activity","Every cloud action is cryptographically signed with the attacker's verified full legal name","Attribution is trivial because cloud logs always contain the attacker's home postal address"], correct:1, explanation:"Shared and ephemeral addressing obscures the source; providers do not publish attacker identities or addresses, so those options are wrong." },
  { id:80935, domain:5, level:1, question:"Which input in a login form most clearly indicates a SQL injection attempt?", options:["A username of normal length containing only standard alphabetic characters and spaces","A password field left completely blank by a user who simply forgot their own credentials","A username value containing ' OR '1'='1' -- intended to alter the backend query logic","An email address submitted in a valid, standard, RFC-compliant addressing format only"], correct:2, explanation:"The tautology payload manipulates the SQL query; a plain name, blank password, or valid email are normal inputs, so they are wrong." },
  { id:80936, domain:5, level:3, question:"What is the primary goal of a stored cross-site scripting attack?", options:["To directly read arbitrary files from the web server's underlying operating system disk","To exhaust the application's database connection pool and cause a denial of service","To brute-force the administrator's password against the application's own login endpoint","To persist malicious script on the server so it executes later in other users' browsers"], correct:3, explanation:"Stored XSS persists script to run in victims' browsers; it does not read server files, exhaust connections, or brute-force logins, so those are wrong." },
  { id:80937, domain:5, level:2, question:"How does a cross-site request forgery attack succeed against a victim?", options:["It tricks an authenticated user's browser into sending an unwanted state-changing request","It injects SQL commands directly into the application's backend relational database queries","It decrypts the TLS session by recovering the web server's private certificate signing key","It floods the target server with traffic from a large distributed botnet to deny service"], correct:0, explanation:"CSRF rides the victim's authenticated session to force actions; it is not SQL injection, TLS breaking, or a DDoS flood, so those are wrong." },
  { id:80938, domain:5, level:3, question:"A web application fetches a URL supplied by the user, reaching internal metadata endpoints. This is which flaw?", options:["Cross-site scripting, which executes attacker-supplied script in a victim's browser context","Server-side request forgery, where the server makes attacker-controlled outbound requests","SQL injection, which manipulates database queries through unsanitized user-supplied input","Clickjacking, which overlays invisible interface elements to hijack a user's genuine clicks"], correct:1, explanation:"SSRF makes the server fetch attacker URLs to reach internal resources; XSS, SQLi, and clickjacking target other layers, so they are wrong." },
  { id:80939, domain:5, level:2, question:"Insecure deserialization vulnerabilities are dangerous primarily because they can lead to what?", options:["Only cosmetic changes to the way error messages are displayed to the application's users","A guaranteed and measurable improvement in application response time under heavy load","Remote code execution when untrusted serialized data is reconstructed by the application","Automatic encryption of all stored data at rest without any additional developer effort"], correct:2, explanation:"Deserializing untrusted data can trigger RCE; it is not cosmetic, a performance gain, or an encryption feature, so those options are wrong." },
  { id:80940, domain:5, level:3, question:"Which weakness falls under the OWASP category of broken authentication?", options:["Serving all application pages exclusively over HTTPS with strong certificate pinning enabled","Encrypting all sensitive database columns using a modern, vetted cryptographic algorithm","Applying strict output encoding to eliminate reflected script injection in the responses","Permitting weak passwords, missing multi-factor auth, and predictable session identifiers"], correct:3, explanation:"Weak passwords, missing MFA, and predictable sessions are broken authentication; HTTPS, encryption, and encoding are protective, so they are wrong." },
  { id:80941, domain:5, level:1, question:"An XML parser processing user input resolves external entities, exposing local files. Which attack is this?", options:["XML External Entity injection abusing entity resolution to read files or reach internal systems","A buffer overflow that overwrites the parser's saved return address on the program stack within the affected environment","A race condition in concurrent write access to a single shared temporary working file","A phishing attack delivering a malicious XML attachment to the victim over corporate email"], correct:0, explanation:"XXE abuses external entity resolution to read files; it is not a buffer overflow, race condition, or phishing, so those are wrong." },
  { id:80942, domain:5, level:2, question:"Which finding is an example of security misconfiguration in a web application?", options:["Enforcing least-privilege database accounts scoped tightly to specific application queries","Leaving default admin credentials, verbose error pages, and directory listing all enabled","Disabling unused HTTP methods and removing detailed stack traces from server responses","Applying a strict content security policy limiting script sources to trusted origins only"], correct:1, explanation:"Default credentials, verbose errors, and directory listing are misconfigurations; the others are hardening measures, so they are wrong." },
  { id:80943, domain:5, level:3, question:"What does a reflected XSS attack require to reach a victim?", options:["The attacker must first gain physical console access to the victim's own workstation hardware","The application must store the malicious payload permanently in its backend database first","The victim must be lured into clicking a crafted link that reflects the script back to them","The victim's browser must have all scripting completely disabled for the attack to work"], correct:2, explanation:"Reflected XSS needs the victim to click a crafted link; it does not need physical access, stored payloads, or disabled scripting, so those are wrong." },
  { id:80944, domain:5, level:2, question:"Which OWASP category covers failures such as missing function-level access checks?", options:["Cryptographic failures, which involve weak or absent protection of sensitive data at rest","Security logging failures, which involve insufficient recording and monitoring of events","Injection, which covers untrusted data being interpreted as a command or database query","Broken access control, where users can act outside their intended permissions and roles"], correct:3, explanation:"Missing function-level checks are broken access control; cryptographic, logging, and injection categories address different flaws, so they are wrong." },
  { id:80945, domain:5, level:3, question:"A parameter change from account_id=100 to account_id=101 exposes another user's data. This is which issue?", options:["Insecure direct object reference under broken access control, missing an ownership check","Reflected cross-site scripting, which executes injected script within the user's own browser","A cryptographic failure caused by the use of an outdated and weak password hashing algorithm","A denial-of-service condition triggered by too many concurrent parameter change requests"], correct:0, explanation:"Changing an ID to reach another's data is IDOR under broken access control; XSS, crypto failure, and DoS are unrelated, so they are wrong." },
  { id:80946, domain:5, level:1, question:"In Apache access logs, which pattern most strongly suggests a directory traversal attempt?", options:["A steady series of HTTP 200 responses for images and stylesheets loaded on the homepage within the affected environment","Repeated requests containing ../ or encoded %2e%2e%2f sequences targeting sensitive file paths","Normal GET requests for the site's public documentation pages that all return status 200","Successful favicon.ico requests recorded from many distinct and legitimate visitor browsers"], correct:1, explanation:"The ../ and encoded traversal sequences indicate the attack; normal 200s for assets, docs, and favicons are benign, so those are wrong." },
  { id:80947, domain:5, level:2, question:"Which IIS log field is most useful for identifying the source of a suspected web attack?", options:["The time-taken field alone, which only measures how long the request processing consumed","The server port field alone, which indicates only the listening port number of the service","The client IP field combined with the requested URI stem and the returned status code","The protocol version field alone, which shows only the HTTP protocol version currently in use"], correct:2, explanation:"c-ip with URI and status identifies source and target; time-taken, port, or protocol alone lack attribution, so those are wrong." },
  { id:80948, domain:5, level:2, question:"A spike of HTTP 500 errors in Nginx logs following crafted requests most likely indicates what?", options:["A normal condition, since HTTP 500 responses always indicate fully successful request handling","A client-side browser caching problem that is entirely unrelated to any actual server behavior","A DNS resolution failure that is preventing the domain name from ever being loaded at all","An application error possibly triggered by malicious input causing backend processing failures"], correct:3, explanation:"A 500 spike after crafted input suggests attack-induced backend errors; 500 is not success, a cache issue, or DNS failure, so those are wrong." },
  { id:80949, domain:5, level:2, question:"Why should web server logs be forwarded to a centralized, write-protected log store?", options:["To prevent attackers from tampering with or deleting the local logs to hide their activity","To permanently reduce the amount of disk space consumed on the central logging server within the affected environment","To make the collected logs unreadable so that no analyst can ever review them later on","To completely eliminate the need to correlate events across multiple separate systems"], correct:0, explanation:"Central write-protected storage preserves integrity; it does not reduce central storage, hide logs, or remove correlation needs, so those are wrong." },
  { id:80950, domain:5, level:1, question:"When analyzing web logs, what does a burst of requests to /wp-login.php from one IP most likely represent?", options:["A search engine crawler routinely indexing the site's publicly available content pages","A brute-force or credential-stuffing attack against the site's authentication endpoint","A content delivery network refreshing its cached copies of the site's static assets","An uptime monitoring probe checking the site availability every few scheduled minutes"], correct:1, explanation:"Bursts against a login endpoint indicate brute force or credential stuffing; crawlers, CDN refresh, and uptime probes do not, so those are wrong." },
  { id:80951, domain:5, level:3, question:"Which log entry detail best helps a handler confirm that an SQL injection reached the database?", options:["The average byte size of the static image responses served during the same time window within the affected environment","The count of successful TLS handshakes negotiated with the web server on that same day","Application or database error messages tied to the request containing the injected query syntax","The total number of favicon requests recorded from all clients during the incident window"], correct:2, explanation:"Database error messages tied to injected syntax confirm the attack reached the DB; image sizes, TLS counts, and favicons do not, so those are wrong." },
  { id:80952, domain:5, level:2, question:"An analyst sees many 404 responses to unusual admin paths from a single IP. What is the likely activity?", options:["A legitimate user who accidentally mistyped the homepage URL a single time in a browser","A scheduled backup job writing files into the web root under a valid service account","A normal image gallery loading many thumbnails from the same shared content directory","Content discovery or directory brute forcing as an attacker probes for hidden resources"], correct:3, explanation:"Many 404s to unusual admin paths indicate content discovery or brute forcing; a typo, backup, or gallery would not produce that pattern, so those are wrong." },
  { id:80953, domain:5, level:3, question:"What is the primary function of a Web Application Firewall in incident prevention?", options:["Inspecting and filtering HTTP traffic to block attacks such as SQL injection and XSS","Encrypting all of the data that is stored in the application's backend relational database","Managing user identity and issuing single sign-on authentication tokens to the end users","Provisioning and automatically scaling the underlying compute infrastructure on demand"], correct:0, explanation:"A WAF filters HTTP traffic to block web attacks; it does not encrypt databases, manage SSO, or provision compute, so those are wrong." },
  { id:80954, domain:5, level:2, question:"How does Runtime Application Self-Protection differ from a traditional WAF?", options:["RASP operates only at the network perimeter and has no visibility into the application logic","RASP is embedded in the application runtime and sees execution context a WAF cannot observe","RASP is purely a static source-code analysis tool that runs only during the build pipeline","RASP only encrypts network traffic and performs no attack detection functionality at all"], correct:1, explanation:"RASP runs inside the app with execution context; it is not perimeter-only, static analysis, or mere encryption, so those are wrong." },
  { id:80955, domain:5, level:1, question:"A WAF in detection-only mode logs a probable SQL injection. What is the appropriate handler action?", options:["Disable the WAF entirely so that these alerts stop cluttering the monitoring dashboard","Ignore the alert because detection-only mode always implies the traffic is completely safe","Investigate the alert, confirm the payload, and then switch to blocking or add mitigations","Delete the associated web logs immediately to reduce the storage consumption they cause"], correct:2, explanation:"Confirming and moving to blocking is correct; disabling the WAF, ignoring alerts, or deleting logs all worsen security, so those are wrong." },
  { id:80956, domain:5, level:3, question:"Which capability distinguishes RASP from perimeter WAF filtering during an incident?", options:["It inspects only the packet headers of inbound traffic before requests reach the server within the affected environment","It relies solely on IP reputation blocklists updated by an external threat feed provider","It functions exclusively during scheduled nightly scans rather than at actual request time","It can observe data flow inside the running application and block malicious execution paths"], correct:3, explanation:"RASP sees internal data flow and blocks execution paths; header-only inspection, IP lists, and nightly scans describe other tools, so those are wrong." },
  { id:80957, domain:5, level:2, question:"What is a common cause of false positives when a WAF is first deployed in blocking mode?", options:["Legitimate application traffic that resembles attack signatures gets blocked by broad rules","The WAF automatically deletes all inbound requests regardless of whether they are malicious","The WAF is physically incapable of ever blocking any genuinely malicious request payload","Blocking mode disables all logging so that no requests can be analyzed by the team later"], correct:0, explanation:"Broad rules can block legitimate lookalike traffic causing false positives; the other statements misdescribe WAF behavior, so they are wrong." },
  { id:80958, domain:5, level:3, question:"A public web server is confirmed compromised. Which containment step also preserves evidence?", options:["Immediately wipe and reinstall the server before collecting any forensic data from it","Isolate the server from the network while first capturing a memory and disk image of it","Leave the server online and internet-facing to observe the attacker's behavior indefinitely","Restart the server repeatedly until the malicious process finally stops reappearing again"], correct:1, explanation:"Isolating while imaging contains the threat and preserves evidence; wiping first, staying exposed, or rebooting destroy or prolong risk, so those are wrong." },
  { id:80959, domain:5, level:2, question:"During eradication of a web shell, which action ensures the malicious artifact is fully removed?", options:["Simply rename the web shell file so that its original request URL no longer resolves for anyone","Block only the single source IP address that first uploaded the web shell to the vulnerable server","Locate and remove the web shell and any persistence, then verify against a known-good baseline","Rotate the site's TLS certificate in order to invalidate the attacker's existing session access"], correct:2, explanation:"Removing the shell and persistence then verifying eradicates it; renaming, single-IP blocking, or cert rotation leave the shell present, so those are wrong." },
  { id:80960, domain:5, level:3, question:"After eradicating a cloud account compromise, what is essential during the recovery phase?", options:["Restore the exact same compromised keys to avoid disrupting any existing service integrations within the affected environment","Skip the validation step entirely to accelerate the return to production as fast as possible","Delete all of the audit logs from the incident window to start again with a fully clean slate","Rotate all credentials and keys, restore from a clean state, and validate before restoring access"], correct:3, explanation:"Rotating credentials, clean restore, and validation are essential; reusing keys, skipping validation, or deleting logs undermine recovery, so those are wrong." },
  { id:80961, domain:5, level:1, question:"Why is establishing a known-good baseline important before recovering a compromised web application?", options:["It provides a trusted reference to confirm restored systems are free of attacker modifications","It guarantees the application will never be successfully attacked again at any point in the future","It automatically encrypts all future network traffic to and from the recovered application server","It removes the need to apply any remaining security patches after the recovery is fully complete"], correct:0, explanation:"A baseline verifies restoration integrity; it does not guarantee future immunity, encrypt traffic, or remove patching needs, so those are wrong." },
  { id:80962, domain:5, level:2, question:"Which recovery action best prevents reinfection after removing malware from a cloud workload?", options:["Restore the previous snapshot that was taken moments before the malware was first detected within the affected environment","Rebuild the instance from a hardened, patched image rather than cleaning the compromised one","Keep the same instance running and only delete the specific malicious files that were found","Disable logging on the rebuilt instance to reduce the noise during recovery monitoring"], correct:1, explanation:"Rebuilding from a hardened image avoids residual compromise; restoring an infected snapshot, cleaning in place, or disabling logging risk reinfection, so those are wrong." },
  { id:80963, domain:5, level:3, question:"During containment of a compromised cloud API key, what is the fastest effective action?", options:["Change the billing contact email on the account to notify the finance team of the misuse","Rename the affected cloud resources so the attacker cannot locate them by their old names","Disable or revoke the specific key immediately to cut the attacker's programmatic access","Increase the account's API rate limit so legitimate services are not throttled by mistake"], correct:2, explanation:"Revoking the key immediately cuts access; changing billing contacts, renaming resources, or raising limits do not stop the key, so those are wrong." },
  { id:80964, domain:5, level:2, question:"Which step belongs in the post-incident phase after a web application breach?", options:["Immediately re-expose the vulnerable endpoint to test whether the attacker returns to it again","Permanently delete all incident records so that auditors cannot review the response later on","Disable monitoring on the recovered application to avoid generating any further alerts","Conduct a lessons-learned review and update controls, detection rules, and the response plan"], correct:3, explanation:"A lessons-learned review with control updates is post-incident work; re-exposing, deleting records, or disabling monitoring are harmful, so those are wrong." },
  { id:80965, domain:5, level:3, question:"A handler must contain an ongoing data exfiltration from a cloud bucket. Which action is most appropriate?", options:["Apply a restrictive bucket policy or block public access to immediately halt the data egress","Wait until the next scheduled maintenance window to change the bucket's access settings safely","Delete the entire bucket right away without first capturing any logs or forensic evidence","Notify only the marketing team while leaving the exposed bucket fully accessible online"], correct:0, explanation:"A restrictive policy or public-access block halts egress at once; waiting, deleting without evidence, or notifying marketing do not, so those are wrong." },
  { id:80966, domain:5, level:1, question:"Which control most directly mitigates broken object level authorization in an API?", options:["Returning more descriptive error messages that reveal internal object identifiers to clients","Enforcing server-side authorization checks that the requester owns each referenced object","Increasing the API rate limit so that authorized users encounter far fewer throttling errors","Compressing every API response payload to reduce the transmitted size sent to the clients"], correct:1, explanation:"Server-side ownership checks stop BOLA; verbose errors help attackers, and rate limits or compression do not enforce authorization, so those are wrong." },
  { id:80967, domain:5, level:2, question:"An API incident shows an attacker enumerating sequential IDs to access other users' records. This is which vulnerability?", options:["Cross-site scripting reflected within an API error response returned directly to the client","A denial-of-service condition caused by an excessive number of concurrent API connections","Broken object level authorization, where missing checks allow access to unauthorized objects","An insecure TLS configuration that allows a downgrade to an unencrypted communication channel"], correct:2, explanation:"Enumerating IDs to reach others' data is BOLA; it is not XSS, a DoS, or a TLS downgrade, so those options are wrong." },
  { id:80968, domain:5, level:2, question:"Which API weakness allows attackers to try large numbers of credentials without being stopped?", options:["Overly strict input validation that rejects any request containing an unexpected character","Excessive use of short-lived tokens that expire before an attacker can even reuse them","Mandatory multi-factor authentication enforced on every single sensitive API call made","Lack of rate limiting and anti-automation controls on the authentication API endpoint"], correct:3, explanation:"Missing rate limiting enables credential stuffing; strict validation, short tokens, and MFA are protective, so those options are wrong." },
  { id:80969, domain:5, level:2, question:"What does excessive data exposure in an API response typically indicate?", options:["The endpoint returns more object fields than the client needs, leaking sensitive data","The endpoint compresses responses so aggressively that some fields become unreadable within the affected environment","The endpoint always requires a valid token before returning any object data at all","The endpoint caches responses at the edge to reduce backend load during peak times"], correct:0, explanation:"Excessive data exposure returns unneeded sensitive fields; aggressive compression, token enforcement, and edge caching are unrelated, so those are wrong." },
  { id:80970, domain:5, level:1, question:"What is the main purpose of a Cloud Access Security Broker?", options:["To physically secure the cloud provider's data centers against unauthorized building entry within the affected environment","To enforce security policy and provide visibility between users and the cloud services they use","To completely replace the need for any identity provider within the organization's environment","To manufacture the physical network hardware that is deployed inside the cloud regions"], correct:1, explanation:"A CASB enforces policy and gives cloud-usage visibility; it does not secure data centers, replace IdPs, or make hardware, so those are wrong." },
  { id:80971, domain:5, level:3, question:"What does Cloud Security Posture Management primarily help organizations do?", options:["Provide traditional antivirus scanning for individual employee laptops and desktop workstations","Encrypt every outbound email message that leaves the corporate mail server automatically","Continuously detect and remediate misconfigurations and compliance drift across cloud resources","Act as the primary network firewall protecting the on-premises data center network segments"], correct:2, explanation:"CSPM finds and fixes cloud misconfigurations and drift; it is not endpoint AV, email encryption, or an on-prem firewall, so those are wrong." },
  { id:80972, domain:5, level:2, question:"Which secure coding practice most directly prevents SQL injection?", options:["Storing all of the database account passwords in plaintext for easy application retrieval within the affected environment","Returning full database error messages to the client to make debugging far more convenient","Disabling all input length limits so that users may submit much longer field values freely","Using parameterized queries or prepared statements that separate code from user-supplied data"], correct:3, explanation:"Parameterized queries prevent SQLi by separating code and data; plaintext passwords, verbose errors, and removed limits increase risk, so they are wrong." },
  { id:80973, domain:5, level:3, question:"Which practice best reduces the blast radius of a compromised cloud credential?", options:["Applying least-privilege IAM policies together with short-lived, tightly scoped temporary credentials","Sharing a single powerful administrative key across all of the applications and their many users within the affected environment","Granting every service in the account the full administrative permission set for convenience","Disabling all logging so that any credential misuse simply cannot be traced by defenders"], correct:0, explanation:"Least privilege and short-lived credentials limit blast radius; shared admin keys, broad grants, and disabled logging expand risk, so they are wrong." },
  { id:80974, domain:5, level:2, question:"How does a WAF help defend a web application while the underlying flaw is being fixed?", options:["It rewrites the vulnerable application source code automatically to remove the flaw entirely","It virtually patches by blocking exploit patterns at the edge until the code is remediated","It encrypts the database so that any injected queries cannot ever read the stored data","It permanently prevents all future vulnerabilities from being introduced into the codebase"], correct:1, explanation:"A WAF virtually patches by blocking exploit patterns; it does not rewrite code, encrypt the DB against injection, or prevent all future flaws, so those are wrong." },
  { id:80975, domain:5, level:1, question:"Which countermeasure best addresses insecure deserialization in a web application?", options:["Increase the server's available memory so the deserialization process completes faster within the affected environment","Return the raw serialized objects to the client so they can validate them themselves","Avoid deserializing untrusted data or use integrity checks and safe, restricted formats","Log every deserialization event but take no action to restrict which types are allowed"], correct:2, explanation:"Avoiding untrusted deserialization with integrity checks addresses the risk; more memory, client-side validation, or log-only do not, so those are wrong." },
  { id:80976, domain:5, level:3, question:"Why should organizations enforce multi-factor authentication on cloud management consoles?", options:["It removes the need to maintain any audit logging of console administrative activity within the affected environment","It automatically encrypts all data stored in every bucket within the cloud account","It guarantees that no misconfiguration can ever occur within the cloud environment","It sharply reduces the impact of stolen or phished passwords used to access the console"], correct:3, explanation:"MFA blunts stolen-password attacks; it does not remove logging needs, encrypt buckets, or prevent misconfiguration, so those options are wrong." },
  { id:80977, domain:5, level:2, question:"Which control provides discovery of shadow IT cloud services used by employees?", options:["A CASB that inspects traffic and logs to reveal unsanctioned cloud application usage","A host-based antivirus agent that scans only local files on each employee laptop device","A network load balancer that distributes inbound requests across several backend web servers","A relational database index that speeds up queries against large application data tables"], correct:0, explanation:"A CASB reveals unsanctioned cloud usage; antivirus, load balancers, and database indexes do not discover shadow IT, so those are wrong." },
  { id:80978, domain:5, level:3, question:"What is the benefit of enabling content security policy headers on a web application?", options:["They encrypt the entire database at rest using a modern block cipher and key rotation within the affected environment","They restrict which script sources may run, mitigating the impact of cross-site scripting","They provide automatic distributed denial-of-service protection at the network perimeter","They replace the need for any server-side input validation of user-supplied parameters"], correct:1, explanation:"CSP restricts script sources to mitigate XSS; it does not encrypt databases, stop DDoS, or replace input validation, so those are wrong." },
  { id:80979, domain:5, level:2, question:"Which practice hardens container images against incident risk before deployment?", options:["Running every container as the root user to avoid any permission-related runtime errors ever within the affected environment","Embedding long-lived cloud credentials directly inside the image for easy service access","Scanning images for vulnerabilities and removing unnecessary packages to shrink attack surface","Disabling image signing so that unsigned images deploy more quickly into the cluster"], correct:2, explanation:"Scanning and minimizing packages hardens images; running as root, embedding credentials, and disabling signing all increase risk, so those are wrong." },
  { id:80980, domain:5, level:3, question:"How does network segmentation limit damage during a web application incident?", options:["It automatically removes all vulnerabilities present in the applications on each segment","It encrypts every packet so that an intruder can never read any traffic on the network","It guarantees that no attacker can ever gain an initial foothold in the environment","It confines a compromise to one segment, preventing lateral movement to other systems"], correct:3, explanation:"Segmentation confines compromise and blocks lateral movement; it does not remove vulns, encrypt all traffic, or prevent initial access, so those are wrong." },
  { id:80981, domain:5, level:1, question:"Which measure best protects against misconfigured storage buckets across many cloud accounts?", options:["Automated posture scanning that flags and remediates public bucket settings continuously","A single manual review of one bucket performed once per calendar year by an outside auditor","Relying on employees to remember to set each bucket private without any tooling support","Disabling all storage logging so that bucket access can no longer be monitored at all"], correct:0, explanation:"Automated posture scanning continuously catches public buckets; annual manual review, memory, and disabled logging are inadequate, so those are wrong." },
  { id:80982, domain:5, level:2, question:"What is the purpose of an incident response runbook for cloud web application incidents?", options:["It permanently prevents any web application vulnerability from being exploited by attackers within the affected environment","It provides predefined, repeatable steps so responders act consistently and quickly under pressure","It replaces the organization's need for logging and monitoring across the cloud environment","It automatically patches every affected system the moment an incident is first detected"], correct:1, explanation:"A runbook standardizes response steps; it does not prevent all exploits, replace monitoring, or auto-patch systems, so those options are wrong." },
  { id:80983, domain:5, level:3, question:"An organization detects unusual API calls creating snapshots and sharing them externally. What is the attacker likely doing?", options:["Performing a routine backup that the operations team scheduled for disaster recovery testing within the affected environment","Running a legitimate cost-optimization task that consolidates unused storage volumes safely","Exfiltrating data by copying volume snapshots and sharing them to an attacker-controlled account","Applying security patches to the volumes before reattaching them to production instances"], correct:2, explanation:"Sharing snapshots externally indicates data exfiltration; routine backups, cost tasks, and patching do not share to outside accounts, so those are wrong." },
  { id:80984, domain:5, level:2, question:"Which cloud logging gap would most hinder investigating a data breach after the fact?", options:["Logs were centralized and write-protected but simply had a longer retention than needed within the affected environment","Alerts were generated for every access but the team also stored the raw logs for review","Access logs existed but merely contained more detail than the investigator required","Audit or data-access logging was never enabled, leaving no record of the resource access"], correct:3, explanation:"Missing audit or data-access logging leaves no record, the worst gap; centralization, extra alerts, or extra detail do not hinder, so those are wrong." },
  { id:80985, domain:5, level:3, question:"A web application returns a full stack trace including database connection strings on error. What is the risk?", options:["Information disclosure that hands attackers internal details useful for further exploitation","Improved security because attackers become confused by the large volume of error text within the affected environment","A performance boost since detailed errors help the server respond to requests faster","Guaranteed protection against SQL injection because the query structure is now visible"], correct:0, explanation:"Verbose stack traces leak internal details aiding attackers; they do not confuse attackers, boost performance, or prevent injection, so those are wrong." },
  { id:80986, domain:5, level:1, question:"Which action helps validate that a web application is safe to return to production after an incident?", options:["Return the application to production immediately without performing any further verification steps","Confirm the vulnerability is patched, run a targeted test, and monitor closely after restoration","Assume the issue is resolved because the malicious files were deleted from the web root earlier","Disable logging during the return so that recovery activity does not generate any alerts"], correct:1, explanation:"Confirming the patch, testing, and monitoring validates safe return; skipping verification, assuming, or disabling logging are unsafe, so those are wrong." },
  { id:80987, domain:5, level:2, question:"Why is time synchronization across cloud and web systems important during incident analysis?", options:["It reduces the overall storage footprint that the collected log files occupy on disk within the affected environment","It encrypts every log entry automatically as it is written to the central log server","Consistent timestamps let handlers correlate events across sources into an accurate timeline","It removes the requirement to collect logs from more than a single system during triage"], correct:2, explanation:"Synchronized time enables accurate cross-source correlation; it does not shrink storage, encrypt logs, or reduce sources needed, so those are wrong." },
  { id:80988, domain:5, level:2, question:"A handler finds an attacker created a new access key for a legitimate service account. What is the best response?", options:["Leave the key in place to avoid interrupting the service account's normal automated jobs within the affected environment","Increase the permissions on the service account so it can better defend itself in future","Ignore the finding because service accounts are inherently trusted within the environment","Delete the unauthorized key, review its activity, and rotate the service account credentials"], correct:3, explanation:"Deleting the rogue key, reviewing activity, and rotating credentials is correct; leaving it, raising permissions, or ignoring it are dangerous, so those are wrong." },
  { id:80989, domain:5, level:2, question:"Which detection approach best identifies anomalous cloud IAM behavior indicating compromise?", options:["Baselining normal identity activity and alerting on deviations such as unusual actions or regions","Blocking all IAM activity outright so that no user can ever perform any privileged action within the affected environment","Relying solely on monthly manual reviews of a static exported list of account permissions","Trusting that any action taken by a valid credential is always legitimate and completely safe"], correct:0, explanation:"Behavioral baselining with anomaly alerts detects IAM compromise; blocking all, monthly manual review, or blind trust are inadequate, so those are wrong." },
  { id:80990, domain:5, level:1, question:"What is a key advantage of using immutable infrastructure for cloud incident recovery?", options:["Instances can be modified freely at runtime, which makes emergency changes much simpler to do","Compromised instances are replaced with fresh, known-good builds rather than patched in place","It eliminates the need to keep any backups because instances can never be compromised at all","It guarantees that deployed applications contain no vulnerabilities of any kind whatsoever"], correct:1, explanation:"Immutable infrastructure replaces compromised instances with clean builds; it does not encourage runtime edits, remove backups, or guarantee zero vulns, so those are wrong." },
  { id:80991, domain:5, level:3, question:"A CASB blocks an upload of sensitive data to an unsanctioned cloud app. Which capability enabled this?", options:["Automatic encryption of the corporate wireless network used by employees while on site within the affected environment","A traditional signature-based antivirus engine scanning files stored on the local disks","Data loss prevention integrated with cloud application visibility and inline policy enforcement","A network router applying quality-of-service rules to prioritize video conferencing traffic"], correct:2, explanation:"CASB DLP with inline enforcement blocked the upload; Wi-Fi encryption, antivirus, and QoS routing do not enforce cloud data policy, so those are wrong." },
  { id:80992, domain:5, level:2, question:"Why is API gateway logging valuable during a web API incident investigation?", options:["It automatically blocks every malicious request before it can ever reach the backend service within the affected environment","It encrypts the API payloads so that investigators cannot inadvertently read sensitive data","It removes the requirement to authenticate any of the requests passing through the gateway","It records request metadata, source, and responses needed to reconstruct attacker interactions"], correct:3, explanation:"Gateway logs capture metadata for reconstruction; they do not auto-block all attacks, encrypt against investigators, or remove auth needs, so those are wrong." },
  { id:80993, domain:5, level:3, question:"Which scenario best illustrates a broken access control failure in a web application?", options:["A standard user directly navigates to an admin URL and gains privileged functions without checks","A user submits a valid password and is correctly granted access to their own account data within the affected environment","An expired session token is properly rejected and the user is redirected to the login page","A request without any authentication cookie is correctly denied access to protected content"], correct:0, explanation:"Reaching admin functions without checks is broken access control; the other scenarios show controls working correctly, so they are wrong." },
  { id:80994, domain:5, level:2, question:"What makes second-order SQL injection harder to detect than classic injection?", options:["The payload is transmitted only over an encrypted channel that no defender can ever inspect within the affected environment","The malicious input is stored first and executed later by a different query, delaying its effect","It works exclusively against static HTML pages that contain no database interaction at all","It requires the attacker to already hold full administrative rights over the database server"], correct:1, explanation:"Stored-then-later-executed input delays the effect, complicating detection; encryption, static pages, and prior admin rights are not the cause, so those are wrong." },
  { id:80995, domain:5, level:1, question:"Which sign in web logs suggests a successful file upload of a malicious script?", options:["A series of HTTP 301 redirects sending browsers from the old domain to the new domain within the affected environment","Repeated successful requests for the same cached CSS file from many legitimate site users","A POST to an upload endpoint followed by GET requests executing a new suspicious script path","A steady stream of HTTP 200 responses for the site's standard product listing pages"], correct:2, explanation:"A POST upload followed by execution of a new script path signals a malicious upload; redirects, cached CSS, and product pages are benign, so those are wrong." },
  { id:80996, domain:5, level:3, question:"How does input validation help prevent multiple classes of web application attacks?", options:["By encrypting the validated input so that the database can no longer read the stored values within the affected environment","By caching the validated input so that repeated requests are served much more quickly later","By logging the input only, without ever deciding whether to accept or reject the request","By rejecting or sanitizing untrusted input, it blocks injection and script-based payloads early"], correct:3, explanation:"Validating and sanitizing input blocks injection and script payloads; encrypting, caching, or log-only do not prevent the attacks, so those are wrong." },
  { id:80997, domain:5, level:2, question:"A web application allows uploading files with any extension to the web root. What is the primary danger?", options:["An attacker can upload a server-side script and execute it to gain remote code execution","The web server will run out of disk space more quickly than the operations team expects","Users may accidentally overwrite one another's uploaded profile images on the shared server","Search engines will index the uploaded files and reduce the site's overall page ranking"], correct:0, explanation:"Unrestricted upload to the web root enables RCE via a server-side script; disk space, overwrites, and SEO are minor by comparison, so those are wrong." },
  { id:80998, domain:5, level:3, question:"Which HTTP response header helps mitigate clickjacking attacks?", options:["Content-Length, which merely tells the browser the size of the returned response body within the affected environment","X-Frame-Options or a frame-ancestors content security policy directive restricting framing","Cache-Control, which only governs how long a response may be cached by intermediaries","Accept-Encoding, which lists the compression algorithms that the client is able to accept"], correct:1, explanation:"X-Frame-Options or frame-ancestors prevents malicious framing; Content-Length, Cache-Control, and Accept-Encoding do not stop clickjacking, so those are wrong." },
  { id:80999, domain:5, level:2, question:"What is the security purpose of an anti-CSRF token in a web form?", options:["It encrypts the entire form submission so that the network cannot observe any of the fields","It compresses the form data to reduce the bandwidth consumed by each individual submission","It ties the request to the user's session so forged cross-site requests are rejected","It caches the form on the server so that repeated submissions load more quickly for users"], correct:2, explanation:"An anti-CSRF token binds requests to the session, defeating forgery; it does not encrypt, compress, or cache the form, so those are wrong." },
  { id:81000, domain:5, level:3, question:"Which finding indicates a possible XML External Entity vulnerability during a web app assessment?", options:["A JSON endpoint that returns the same fixed error message for every malformed request received","A static image endpoint that always responds with the identical cached picture file every time","A login page that consistently rejects any password shorter than the required minimum length","An XML endpoint that returns local file contents when a crafted external entity is supplied"], correct:3, explanation:"Returning local file contents from a crafted entity indicates XXE; fixed JSON errors, static images, and length checks do not, so those are wrong." },
  { id:81001, domain:5, level:1, question:"Why is enabling MFA delete on critical cloud storage buckets a useful control?", options:["It prevents attackers with stolen credentials from permanently deleting stored objects easily","It automatically classifies every stored object by its sensitivity level and content type within the affected environment","It compresses all stored objects to significantly reduce the monthly storage costs incurred","It guarantees that stored objects can never be read by any unauthorized external party"], correct:0, explanation:"MFA delete blocks easy deletion by credential thieves; it does not classify, compress, or by itself prevent reads, so those options are wrong." },
  { id:81002, domain:5, level:2, question:"An attacker disables cloud logging shortly after gaining access. What defensive measure counters this?", options:["Store all of the logs only on the same compromised instance to keep the collection process simple within the affected environment","Send logs to a separate, tightly controlled account so they persist even if the source is tampered","Rely entirely on the attacker leaving the default logging configuration completely untouched","Disable logging proactively so there is nothing at all for the attacker to tamper with later"], correct:1, explanation:"Shipping logs to a separate controlled account preserves them despite tampering; local-only storage, trusting the attacker, or disabling logging fail, so those are wrong." },
  { id:81003, domain:5, level:3, question:"Which cloud IAM practice reduces the risk of standing privileged access being abused?", options:["Assigning permanent administrator rights to every developer to remove access-request friction within the affected environment","Sharing one root account across the whole team so that the access is simple to coordinate","Just-in-time elevation that grants privileged roles temporarily and revokes them automatically","Disabling all access reviews so that permissions are never questioned once they are granted"], correct:2, explanation:"Just-in-time temporary elevation limits standing privilege abuse; permanent admin, shared root, and no reviews all increase risk, so those are wrong." },
  { id:81004, domain:5, level:2, question:"What is a primary security concern with serverless (function-as-a-service) workloads during incidents?", options:["Serverless functions run indefinitely, so investigators always have unlimited time to capture data","Functions expose full operating-system shells that make host forensics trivial to perform easily","Serverless platforms retain a complete disk image of every function invocation forever always","Short-lived execution and limited host access make traditional forensic capture difficult"], correct:3, explanation:"Ephemeral execution and limited host access hinder forensic capture; functions are not long-running, shell-exposing, or fully imaged, so those are wrong." },
  { id:81005, domain:5, level:3, question:"Which practice helps ensure cloud incident responders can access needed logs quickly?", options:["Predefining break-glass roles and log-access permissions before an incident actually occurs","Requesting all necessary permissions only after the incident has already been fully contained","Storing every log exclusively on encrypted media that no responder is ever permitted to open","Granting responders no standing access and relying on ad-hoc approvals during the crisis"], correct:0, explanation:"Predefined break-glass access lets responders reach logs fast; post-incident requests, sealed media, and ad-hoc-only approval slow response, so those are wrong." },
  { id:81006, domain:5, level:1, question:"A cloud workload communicates with a known malicious IP flagged by threat intelligence. What should the handler do first?", options:["Immediately terminate the workload without capturing any of the connection or system logs within the affected environment","Investigate and contain the affected workload while preserving logs of the suspicious connection","Add the malicious IP to an allow list so the connection is no longer flagged by tooling","Ignore the alert because outbound connections are always initiated by legitimate software"], correct:1, explanation:"Investigating and containing while preserving logs is correct; terminating without logs, allow-listing, or ignoring the alert are wrong." },
  { id:81007, domain:5, level:2, question:"Which statement about cloud snapshots as forensic artifacts is accurate?", options:["A snapshot automatically includes the full volatile memory contents of the running instance within the affected environment","A snapshot cannot be used as evidence because cloud data is inherently inadmissible in court","A snapshot captures the volume state at a point in time and should be hashed to prove integrity","A snapshot permanently locks the source volume so no further changes can ever be written"], correct:2, explanation:"Snapshots capture point-in-time volume state and should be hashed; they omit memory, are not inherently inadmissible, and do not lock the source, so those are wrong." },
  { id:81008, domain:5, level:2, question:"Why should a handler capture instance memory before shutting down a compromised cloud VM?", options:["Memory contains a complete copy of every log the instance ever wrote to its persistent disk within the affected environment","Shutting down first automatically transfers the memory contents into a forensic image file","Memory capture is unnecessary because all evidence is always written to durable storage first","Volatile artifacts like running processes and injected code exist only in memory and vanish on shutdown"], correct:3, explanation:"Volatile memory artifacts vanish on shutdown, so capture first; memory is not a full log copy, shutdown does not image it, and not all evidence is on disk, so those are wrong." },
  { id:81009, domain:5, level:2, question:"Which of the following is a hardening step for a public-facing web server?", options:["Removing unused modules, disabling directory listing, and applying the latest security patches","Enabling detailed stack traces in production so end users can help diagnose any errors seen within the affected environment","Running the web server process as the root or administrator account purely for convenience","Opening all inbound ports so that future services never require any firewall reconfiguration"], correct:0, explanation:"Removing modules, disabling listing, and patching harden the server; verbose traces, root process, and open ports weaken it, so those are wrong." },
  { id:81010, domain:5, level:1, question:"What is the main risk of leaving debug mode enabled on a production web framework?", options:["It slightly increases the page load time but poses no genuine security concern for the application within the affected environment","It can expose sensitive configuration, stack traces, and even a code-execution console to attackers","It only affects the developers' local machines and never reaches the production environment at all","It automatically encrypts all traffic, which unnecessarily consumes server processing power"], correct:1, explanation:"Debug mode can leak config, traces, and consoles enabling code execution; it is a real risk, reaches production, and does not encrypt traffic, so those are wrong." },
  { id:81011, domain:5, level:3, question:"A handler must determine the scope of a cloud breach. Which data source is most useful first?", options:["The marketing department's public social media posts about recent company announcements made within the affected environment","The physical badge-access records for the corporate office building's main front entrance","Centralized audit and management-plane logs showing which identities accessed which resources","The provider's public status page describing the regional service availability history"], correct:2, explanation:"Audit and management-plane logs reveal breach scope; social media, badge records, and status pages do not, so those options are wrong." },
  { id:81012, domain:5, level:2, question:"Which is a valid reason to involve the cloud provider during a serious incident?", options:["They will assume complete legal liability for the breach on the customer's behalf immediately","They can retroactively erase all evidence that the incident ever actually took place at all","They are obligated to identify the attacker by full legal name within one hour of the request","They may supply platform-level logs or take actions the customer cannot perform independently"], correct:3, explanation:"Providers can supply platform logs or take privileged actions; they do not assume liability, erase evidence, or name attackers on demand, so those are wrong." },
  { id:81013, domain:5, level:3, question:"Why is tagging cloud resources helpful during incident response?", options:["Tags let responders quickly identify ownership, environment, and criticality of affected resources","Tags automatically encrypt the tagged resources against any form of unauthorized outside access within the affected environment","Tags physically isolate the resources from the rest of the network during an active incident","Tags guarantee that the tagged resources can never be compromised by any attacker at all"], correct:0, explanation:"Tags speed identification of ownership and criticality; they do not encrypt, isolate, or immunize resources, so those options are wrong." },
  { id:81014, domain:5, level:2, question:"Which approach best detects a compromised web application shell communicating outbound?", options:["Reviewing only the inbound firewall logs while ignoring all outbound network connections entirely","Monitoring egress traffic and web server process behavior for unexpected outbound connections","Trusting that any traffic originating from the web server is inherently safe and legitimate always","Disabling network monitoring on the web server to reduce the volume of generated alerts"], correct:1, explanation:"Monitoring egress and process behavior detects shell callbacks; inbound-only review, blind trust, and disabling monitoring miss it, so those are wrong." },
  { id:81015, domain:5, level:1, question:"What is a benefit of using a WAF managed rule set for common web attacks?", options:["It permanently removes the need to ever patch the underlying web application code again","It guarantees exactly zero false positives for every legitimate request the application receives","It provides vendor-maintained protections against known attack patterns updated over time","It replaces the requirement for any authentication on the protected application entirely"], correct:2, explanation:"Managed rule sets give maintained protection against known patterns; they do not remove patching, guarantee zero false positives, or replace auth, so those are wrong." },
  { id:81016, domain:5, level:3, question:"A cloud key management service key is suspected compromised. What is the appropriate action?", options:["Continue using the same key because rotating it would inconvenience the existing applications","Publish the key details internally so every team is aware of exactly which key was affected","Delete all data the key protected so the compromised key can no longer decrypt anything","Rotate or disable the key, assess what it protected, and re-encrypt affected data as needed"], correct:3, explanation:"Rotating or disabling the key and re-encrypting is correct; reuse, publishing details, or deleting protected data are wrong." },
  { id:81017, domain:5, level:2, question:"Which condition best indicates a Kubernetes cluster has been compromised for cryptomining?", options:["Newly deployed pods running unknown images with sustained high CPU and mining-pool traffic","A single pod restarting occasionally due to a failed readiness probe during a normal deployment","Expected autoscaling adding nodes in response to a legitimate rise in the application demand","A routine rolling update replacing pods gradually with a newly built application image"], correct:0, explanation:"Unknown high-CPU pods with mining-pool traffic indicate cryptomining; probe restarts, autoscaling, and rolling updates are normal, so those are wrong." },
  { id:81018, domain:5, level:3, question:"Why is least privilege important for service accounts used by web applications?", options:["It automatically encrypts all traffic between the application and its backend database server","It limits what an attacker can do if the application or its credentials become compromised","It guarantees the application will never contain any exploitable software vulnerability at all","It removes the need to monitor the service account's activity for any suspicious behavior"], correct:1, explanation:"Least privilege limits attacker impact after compromise; it does not encrypt traffic, remove vulns, or remove monitoring needs, so those are wrong." },
  { id:81019, domain:5, level:2, question:"Which practice supports faster recovery after a cloud web application incident?", options:["Keeping the only copy of the production environment on a single unbacked-up instance always","Avoiding documentation so responders can improvise freely during every recovery effort later","Maintaining tested infrastructure-as-code and backups to rebuild clean environments quickly","Storing the backups on the same compromised system so they are convenient to reach quickly"], correct:2, explanation:"Tested IaC and backups enable rapid clean rebuilds; a single unbacked instance, no documentation, and co-located backups hinder recovery, so those are wrong." },
  { id:81020, domain:5, level:3, question:"What is a common consequence of not validating redirect targets in a web application?", options:["Automatic remote code execution on the web server every time a redirect is processed for a user within the affected environment","Complete loss of the application's entire database because redirects overwrite stored records","A guaranteed denial of service whenever more than one redirect is issued per single second","Open redirect abuse, where attackers craft trusted-looking links that send victims to malicious sites"], correct:3, explanation:"Unvalidated redirects enable open redirect phishing; they do not cause RCE, database loss, or guaranteed DoS, so those options are wrong." },
  { id:81021, domain:5, level:1, question:"Which log correlation helps confirm an account takeover in a cloud web application?", options:["A successful login from a new location followed immediately by sensitive configuration changes","A series of failed login attempts that were all correctly blocked by the authentication system","A normal password change performed by the user from their usual device and network location","Routine read-only dashboard views from the user's registered office IP during normal work hours"], correct:0, explanation:"New-location login followed by sensitive changes indicates takeover; blocked failures, normal password changes, and routine views are benign, so those are wrong." },
  { id:81022, domain:5, level:2, question:"Why should incident responders avoid using production credentials when investigating a breach?", options:["Production credentials cannot technically read any of the logs required for the investigation","Reusing potentially compromised credentials can alert the attacker or cause further exposure","Investigators are legally forbidden from ever viewing any production system during an incident","Using separate credentials makes the investigation take significantly longer to fully complete"], correct:1, explanation:"Avoiding possibly compromised production credentials prevents tipping off attackers or exposure; the other claims are false, so they are wrong." },
  { id:81023, domain:5, level:3, question:"What does a sudden creation of many cloud resources across regions often indicate?", options:["A normal deployment that the platform team scheduled and communicated well in advance to all","An automated cost-savings routine consolidating existing resources into far fewer regions","Resource abuse such as cryptomining spun up by an attacker using compromised credentials","A routine compliance scan that reads resource metadata without creating anything new at all"], correct:2, explanation:"Mass resource creation across regions signals abuse like cryptomining; planned deploys, consolidation, and read-only scans do not create sprawl, so those are wrong." },
  { id:81024, domain:5, level:2, question:"Which measure most improves detection of web application attacks over time?", options:["Leaving the default WAF configuration unchanged permanently to avoid any tuning effort at all","Turning off alerting for endpoints that generated any false positive even a single time before","Reducing log retention to a few hours so that the storage costs remain as low as possible","Continuously tuning WAF rules and alerts based on observed traffic and past incident patterns"], correct:3, explanation:"Continuous tuning of rules and alerts improves detection; static defaults, disabling noisy alerts, and short retention degrade it, so those are wrong." },
  { id:81025, domain:5, level:3, question:"A handler discovers an S3 bucket policy allowing s3:GetObject to Principal '*'. What does this mean?", options:["Any anonymous user on the internet can read objects in the bucket, indicating public exposure","Only authenticated users within the same account can read the objects stored in the bucket within the affected environment","The bucket is fully private because the wildcard restricts access to internal services only","The policy encrypts all objects so no one can read them without the proper decryption key"], correct:0, explanation:"A wildcard principal on GetObject means anyone can read the objects publicly; it is not account-only, private, or an encryption control, so those are wrong." },
  { id:81026, domain:5, level:1, question:"Which practice reduces the risk of leaked secrets in cloud web application deployments?", options:["Committing credentials into the source repository so the whole team can access them easily","Using a managed secrets store and injecting credentials at runtime instead of hardcoding them","Emailing production secrets to developers whenever they first join the application project team","Embedding long-lived API keys directly into client-side JavaScript purely for convenience"], correct:1, explanation:"A managed secrets store with runtime injection reduces leaks; committing, emailing, or embedding secrets exposes them, so those are wrong." },
  { id:81027, domain:5, level:2, question:"What is the primary reason to restrict outbound internet access from cloud workloads?", options:["It automatically patches every vulnerability present in the workload's installed software packages","It guarantees that inbound attacks against the workload can never possibly succeed at all","It limits an attacker's ability to exfiltrate data or reach command-and-control servers","It removes the need to monitor the workload for any suspicious internal lateral activity"], correct:2, explanation:"Egress restriction limits exfiltration and C2; it does not patch, block all inbound attacks, or remove monitoring needs, so those are wrong." },
  { id:81028, domain:5, level:2, question:"Which artifact best helps reconstruct the timeline of a web application attack?", options:["A single screenshot of the application's homepage taken after the incident had already concluded","The attacker's own written description of events voluntarily provided in a public forum post","The application's marketing brochure describing its intended features and business benefits","Correlated web server, application, and WAF logs aligned by synchronized accurate timestamps"], correct:3, explanation:"Correlated, time-aligned logs reconstruct the timeline; a screenshot, attacker's account, or brochure are not reliable evidence, so those are wrong." },
  { id:81029, domain:5, level:2, question:"Why is it risky to expose a database management port directly to the internet?", options:["Attackers can attempt direct brute-force or exploit attacks against the exposed database service","Exposing the port automatically encrypts all of the database traffic against any interception within the affected environment","It improves query performance by reducing the number of intermediate network hops involved","It is required for the database to function and therefore poses no additional security risk"], correct:0, explanation:"An internet-exposed DB port invites direct attacks; it does not encrypt traffic, boost performance, or represent a required safe configuration, so those are wrong." },
  { id:81030, domain:5, level:1, question:"Which step helps prevent recurrence after remediating a misconfigured cloud resource?", options:["Manually fix the single resource and take no action to prevent the same mistake elsewhere later","Implement guardrails such as policy-as-code that block the insecure configuration going forward","Document the fix privately and rely on individuals to remember it during any future changes","Disable the monitoring that originally detected the misconfiguration to reduce the alert noise"], correct:1, explanation:"Policy-as-code guardrails prevent recurrence; a one-off manual fix, private notes, or disabling detection do not, so those options are wrong." },
  { id:81031, domain:5, level:3, question:"What is the value of threat intelligence during cloud and web incident handling?", options:["It automatically remediates every incident without any analyst involvement whatsoever needed within the affected environment","It replaces the organization's need to keep any of its own logs or monitoring data at all","It provides context on attacker tools and indicators to guide detection and containment decisions","It guarantees the organization will never be targeted by any future attack campaign ever"], correct:2, explanation:"Threat intel provides context to guide response; it does not auto-remediate, replace logging, or guarantee immunity, so those are wrong." },
  { id:81032, domain:5, level:2, question:"Why is separation of duties useful in managing cloud administrative access?", options:["It automatically encrypts every administrative session so no action can ever be observed at all within the affected environment","It guarantees that administrators can never make any configuration mistake in the environment","It removes the need to log administrative actions since duties are already divided among staff","It prevents a single compromised or malicious admin from unilaterally abusing critical operations"], correct:3, explanation:"Separation of duties limits unilateral abuse; it does not encrypt sessions, prevent all mistakes, or remove logging needs, so those are wrong." },
  { id:81033, domain:5, level:3, question:"Which is an effective way to detect misuse of stolen cloud credentials early?", options:["Alerting on impossible-travel logins and API calls from atypical locations or new devices","Waiting for the monthly billing statement to reveal any unexpected charges to the account","Assuming any successful authentication is legitimate because the password was entered correctly","Disabling geolocation data in logs so that login origins are no longer tracked or recorded"], correct:0, explanation:"Impossible-travel and atypical-location alerting detects credential misuse early; billing waits, blind trust, and removing geodata all fail, so those are wrong." },
  { id:81034, domain:5, level:2, question:"What is the purpose of rate limiting on a web application login endpoint?", options:["To permanently encrypt every password stored within the application's backend user database","To slow automated brute-force and credential-stuffing attempts against user accounts","To speed up legitimate logins by caching each user's password directly in browser memory","To remove the requirement for users to ever provide a second authentication factor at all"], correct:1, explanation:"Rate limiting slows automated credential attacks; it does not encrypt stored passwords, cache them, or replace MFA, so those options are wrong." },
  { id:81035, domain:5, level:1, question:"Which cloud service model gives the customer the most responsibility for security patching?", options:["Software as a Service, where the vendor handles nearly the entire technology stack for you","A fully managed serverless platform where the provider patches all runtime components itself","Infrastructure as a Service, where the customer manages the guest OS and everything above it","A managed database service where the provider handles the underlying engine patching entirely"], correct:2, explanation:"IaaS gives the customer the most patching duty; SaaS, serverless, and managed databases shift patching to the provider, so those are wrong." },
  { id:81036, domain:5, level:3, question:"What is the first priority when an active cloud incident is detected?", options:["Publicly disclose the breach on social media before any facts have been confirmed at all within the affected environment","Delete the affected resources immediately so the attacker has nothing left to exploit further","Assign blame to an individual team member before the root cause is even understood clearly","Contain the threat to limit spread while preserving evidence for later investigation and analysis"], correct:3, explanation:"Containment with evidence preservation is the priority; premature disclosure, deletion, or blame do not help the response, so those are wrong." },
  { id:81037, domain:5, level:2, question:"Which is a defining characteristic of a distributed denial-of-service attack on a web application?", options:["Overwhelming the application with traffic from many sources to exhaust its resources","Silently reading sensitive database records without generating any noticeable traffic at all","Modifying the application's source code to insert a hidden backdoor for later reuse","Encrypting the web server's files and demanding a ransom for the decryption keys"], correct:0, explanation:"DDoS floods from many sources exhaust resources; silent reads, code modification, and ransom encryption describe other attacks, so those are wrong." },
  { id:81038, domain:5, level:3, question:"Why are cloud API keys attractive targets for attackers?", options:["They are impossible to revoke once issued and therefore provide permanent guaranteed access within the affected environment","They can grant broad programmatic access to resources and are often leaked in code or configs","They automatically bypass all logging so their use can never be detected by any defender","They only work from a single fixed IP address, which limits their overall usefulness"], correct:1, explanation:"Broad programmatic access and frequent leakage make keys attractive; keys can be revoked, are logged, and are not IP-locked, so those are wrong." },
  { id:81039, domain:5, level:2, question:"What does the term lateral movement describe in a cloud incident?", options:["The provider automatically balancing workloads evenly across the available compute zones within the affected environment","A user relocating their application from one cloud region to another for lower latency","An attacker pivoting from one compromised resource to reach additional systems or accounts","The routine replication of storage objects between buckets for durability and backup"], correct:2, explanation:"Lateral movement is pivoting to more systems; load balancing, region moves, and replication are normal operations, so those are wrong." },
  { id:81040, domain:5, level:3, question:"Which cloud misconfiguration most commonly leads to accidental data exposure?", options:["Excessively strict firewall rules that block all legitimate application traffic by default","Enabling encryption at rest on every storage bucket in the entire cloud account","Applying multi-factor authentication to every administrative user in the organization","Overly permissive access controls on storage or databases left open to the public internet"], correct:3, explanation:"Permissive public access controls cause exposure; strict rules, encryption, and MFA are protective, not causes, so those are wrong." },
  { id:81041, domain:5, level:1, question:"What is a benefit of centralized identity federation for cloud incident response?", options:["Access can be revoked in one place, quickly cutting a compromised user off from all systems","Each application maintains its own separate password store, simplifying isolated resets","Users memorize a unique password for every cloud service to reduce single points of failure","Identity events are never logged, which reduces the volume of data responders must review"], correct:0, explanation:"Central federation lets responders revoke access once across systems; separate stores, many passwords, and no logging hinder response, so those are wrong." },
  { id:81042, domain:5, level:2, question:"Which practice helps ensure web application logs are useful for incident investigation?", options:["Logging only successful page views while discarding every error and security-relevant event within the affected environment","Logging authentication events, input anomalies, and errors with enough context and timestamps","Overwriting the previous day's logs each morning to keep total storage usage very low","Storing logs solely in the browser's local storage on each visiting client's device"], correct:1, explanation:"Rich, contextual, timestamped logging aids investigation; dropping errors, overwriting, or client-only storage undermine it, so those are wrong." },
  { id:81043, domain:5, level:3, question:"An attacker uses a valid but stolen session cookie to access a web application. What is this called?", options:["SQL injection, where crafted input manipulates the application's backend database queries","A brute-force attack, where many password guesses are tried against the login endpoint","Session hijacking, where a stolen or predicted session token grants unauthorized access","A phishing attack, where the victim is tricked into revealing their login credentials"], correct:2, explanation:"Using a stolen session token is session hijacking; SQLi, brute force, and phishing are different techniques, so those options are wrong." },
  { id:81044, domain:5, level:2, question:"Which mitigation reduces the risk of session hijacking in a web application?", options:["Storing session tokens in plaintext within the page's HTML for easy client-side access","Reusing the same static session token across every user to simplify server-side handling","Extending session lifetimes indefinitely so that users never have to log in again at all","Using secure, HttpOnly cookies with short lifetimes and binding sessions to context"], correct:3, explanation:"Secure, HttpOnly, short-lived, context-bound cookies reduce hijacking; plaintext tokens, shared tokens, and endless sessions increase risk, so those are wrong." },
  { id:81045, domain:5, level:3, question:"What is the purpose of a honeypot in cloud and web incident detection?", options:["To deploy a decoy resource that attracts attackers and reveals their techniques safely","To serve as the primary production database handling all real customer transactions within the affected environment","To permanently block every inbound connection to the protected production environment","To automatically patch all vulnerabilities discovered across the cloud environment"], correct:0, explanation:"A honeypot is a decoy that reveals attacker techniques; it is not a production database, a blocker, or a patcher, so those options are wrong." },
  { id:81046, domain:5, level:1, question:"Which indicator suggests an insider is exfiltrating data from a cloud environment?", options:["A single failed login that the authentication system correctly blocked and then logged within the affected environment","Large, unusual downloads of sensitive data by an account outside its normal access pattern","Routine scheduled reports being generated by an account during its normal business hours","A password reset performed by the user through the standard self-service reset workflow"], correct:1, explanation:"Unusual bulk downloads outside normal patterns suggest exfiltration; a blocked login, routine reports, and a normal reset are benign, so those are wrong." },
  { id:81047, domain:5, level:2, question:"Why is encrypting data at rest and in transit important for cloud web applications?", options:["It removes the need to control who is authorized to access the application's data at all within the affected environment","It guarantees that no software vulnerability can ever be exploited in the application code","It protects sensitive data from disclosure even if storage or network access is compromised","It automatically prevents any misconfiguration of the cloud resources storing the data"], correct:2, explanation:"Encryption protects data if access is compromised; it does not replace access control, remove vulns, or prevent misconfiguration, so those are wrong." },
  { id:81048, domain:5, level:2, question:"Which action best supports evidence integrity during cloud incident handling?", options:["Editing the collected logs to remove entries that seem irrelevant to the current investigation","Storing all evidence only on the same system that was compromised during the incident","Sharing raw evidence widely with staff who have no role in the ongoing investigation","Hashing acquired artifacts and documenting a clear chain of custody for each item collected"], correct:3, explanation:"Hashing and chain-of-custody documentation support integrity; editing logs, co-locating with the compromise, or oversharing undermine it, so those are wrong." },
  { id:81049, domain:5, level:2, question:"What distinguishes a web defacement incident from a data breach?", options:["Defacement alters visible site content, while a breach involves unauthorized access to data","Defacement always steals customer payment data, while a breach only changes the homepage within the affected environment","Defacement is undetectable, while a breach is always immediately visible to every user","Defacement affects only databases, while a breach affects only static image files"], correct:0, explanation:"Defacement changes visible content while a breach exposes data; the other statements invert or confuse the two, so those are wrong." },
  { id:81050, domain:5, level:1, question:"Which cloud-native control can automatically remediate a newly public storage bucket?", options:["A content delivery network that simply caches the public objects closer to end users within the affected environment","A CSPM or automated policy engine that detects and reverts the public setting on the bucket","A load balancer that distributes read requests for the bucket across many backend nodes","A billing alert that notifies the finance team about the increased data transfer costs"], correct:1, explanation:"A CSPM or policy engine can auto-revert public settings; a CDN, load balancer, and billing alert do not remediate, so those options are wrong." },
  { id:81051, domain:5, level:3, question:"What is the risk of storing secrets in a container image layer?", options:["The secret is automatically rotated every time the container image is rebuilt and pushed","The secret becomes readable only to the single container that first uses it at runtime","Anyone who pulls the image can extract the embedded secret from its filesystem layers","The secret is encrypted by the registry so it can never be recovered by any attacker"], correct:2, explanation:"Secrets in image layers can be extracted by anyone pulling the image; they are not auto-rotated, isolated, or registry-encrypted, so those are wrong." },
  { id:81052, domain:5, level:2, question:"Which sign indicates that a web application firewall rule is generating false negatives?", options:["Legitimate user requests are blocked even though they contain no malicious content at all within the affected environment","The WAF dashboard displays a high volume of correctly blocked attack attempts each hour","The WAF successfully logs every request it inspects along with the corresponding verdict","Known malicious requests pass through undetected and reach the vulnerable application backend"], correct:3, explanation:"False negatives mean malicious requests pass undetected; blocked legitimate traffic is a false positive, and the others show correct operation, so those are wrong." },
  { id:81053, domain:5, level:3, question:"Why is a well-defined communication plan important during a cloud incident?", options:["It ensures stakeholders, legal, and affected parties receive accurate and timely information","It replaces the need to perform any technical containment or eradication of the threat within the affected environment","It guarantees that the incident will never recur in the future under any circumstances","It automatically encrypts every message sent between the members of the response team"], correct:0, explanation:"A communication plan ensures timely, accurate updates; it does not replace containment, prevent recurrence, or encrypt messages, so those are wrong." },
  { id:81054, domain:5, level:2, question:"Which factor increases the difficulty of collecting volatile data from a cloud instance?", options:["The provider mailing a physical copy of the instance's memory to the investigator on request","Limited low-level host access and the instance's potential to be terminated by autoscaling","Guaranteed indefinite retention of all volatile memory by the cloud platform automatically","The complete absence of any network connectivity to the running cloud instance at all"], correct:1, explanation:"Limited host access and possible termination hinder volatile collection; providers do not mail memory, retain it indefinitely, or remove connectivity, so those are wrong." },
  { id:81055, domain:5, level:1, question:"What is the security benefit of using short-lived tokens instead of long-lived API keys?", options:["Short-lived tokens can never be stolen because they are transmitted only over the network","Short-lived tokens grant broader permissions, which makes automation simpler to manage","A leaked short-lived token expires quickly, sharply limiting the window of possible abuse","Short-lived tokens remove the need to authenticate the requesting client altogether"], correct:2, explanation:"Short-lived tokens limit the abuse window when leaked; they can still be stolen, do not grant broader rights, and do not remove authentication, so those are wrong." },
  { id:81056, domain:5, level:3, question:"Which is a recommended response to a confirmed cross-site scripting vulnerability in production?", options:["Ignore the finding because cross-site scripting only affects the individual user's own browser","Disable all logging on the affected pages so the exploitation attempts stop being recorded","Publicly post the exact exploit payload before the vulnerability has been patched at all","Apply output encoding and input validation, then deploy the fix and verify it is effective"], correct:3, explanation:"Encoding, validation, deployment, and verification remediate XSS; ignoring it, disabling logs, or publishing the exploit are harmful, so those are wrong." },
  { id:81057, domain:5, level:2, question:"What does the principle of defense in depth mean for cloud web application security?", options:["Multiple layered controls so that if one fails, others still protect the application and data","A single strong perimeter firewall that alone is sufficient to stop every possible attack within the affected environment","Relying entirely on the cloud provider to secure the customer's applications and data","Removing security controls to reduce complexity and improve application performance"], correct:0, explanation:"Defense in depth layers multiple controls; a single firewall, total provider reliance, or removing controls contradict it, so those options are wrong." },
  { id:81058, domain:5, level:3, question:"Which log field helps distinguish automated bot traffic from human users in web logs?", options:["The response body size alone, which reveals nothing about who initiated the request within the affected environment","The user-agent string combined with request rate and access patterns across the session","The TLS protocol version alone, which is shared by both bots and legitimate browsers","The favicon request count alone, which does not reliably identify automated clients"], correct:1, explanation:"User-agent with rate and pattern helps distinguish bots; body size, TLS version, or favicon count alone are not reliable indicators, so those are wrong." },
  { id:81059, domain:5, level:2, question:"Why should a compromised cloud service account be disabled rather than just monitored?", options:["Disabling accounts is never necessary because monitoring alone always stops the attacker within the affected environment","Monitoring automatically revokes the attacker's access without any further action needed","Continued active access lets the attacker cause further damage while the account remains usable","A compromised service account cannot perform any harmful action once it is being watched"], correct:2, explanation:"Disabling stops ongoing damage; monitoring alone leaves access active, does not revoke, and does not neutralize the account, so those are wrong." },
  { id:81060, domain:5, level:3, question:"Which describes a supply-chain risk affecting cloud web applications?", options:["A single end user forgetting their password and using the self-service reset workflow within the affected environment","The provider performing scheduled maintenance on its own internal network infrastructure","An administrator enabling multi-factor authentication on their own personal account","A compromised third-party dependency or image introduces malicious code into the application"], correct:3, explanation:"A compromised dependency or image is a supply-chain risk; a forgotten password, provider maintenance, and enabling MFA are not, so those are wrong." },
  { id:81061, domain:5, level:1, question:"What is the purpose of immutable, append-only logging in cloud environments?", options:["To ensure log entries cannot be altered or deleted, preserving them for reliable investigation","To reduce log storage costs by automatically discarding older entries after a short period within the affected environment","To make the logs faster to search by keeping only a small subset of recent events","To encrypt the logs so that authorized investigators are unable to read them at all"], correct:0, explanation:"Append-only logging preserves entries against tampering; it is not for cost reduction, subset retention, or blocking investigators, so those are wrong." },
  { id:81062, domain:5, level:2, question:"Which detection method best identifies data exfiltration to an unusual external destination?", options:["Inbound port scanning detection that only watches for connection attempts from outside within the affected environment","Egress traffic monitoring that flags large transfers to unfamiliar or untrusted endpoints","CPU utilization alerts that fire only when a workload's processor usage is extremely low","Disk space alerts that notify the team when available storage runs unexpectedly high"], correct:1, explanation:"Egress monitoring flags unusual outbound transfers; inbound scan detection, low-CPU alerts, and high-disk alerts do not catch exfiltration, so those are wrong." },
  { id:81063, domain:5, level:3, question:"Why is patching known vulnerabilities essential in web application incident prevention?", options:["Patching guarantees the application will never experience any downtime for any reason at all within the affected environment","Patching automatically encrypts the application's stored data without any developer effort","Unpatched flaws are frequently exploited by attackers using widely available public exploit code","Patching removes the need to monitor the application for any suspicious behavior thereafter"], correct:2, explanation:"Patching closes flaws exploited by public exploit code; it does not guarantee uptime, encrypt data, or remove monitoring needs, so those are wrong." },
  { id:81064, domain:5, level:2, question:"Which is a proper containment measure for a compromised container in a cluster?", options:["Deploy many additional copies of the compromised container to dilute the attacker's control","Grant the container elevated privileges so security tooling can inspect it more thoroughly","Ignore the container because orchestration will eventually reschedule it somewhere else","Isolate or terminate the affected pod and cordon the node while preserving relevant logs"], correct:3, explanation:"Isolating or terminating the pod and cordoning the node contains it; scaling it, elevating privileges, or ignoring it worsen the situation, so those are wrong." },
  { id:81065, domain:5, level:3, question:"What is the main goal of the eradication phase in incident handling?", options:["To remove the root cause and all attacker artifacts so the threat cannot persist or return","To immediately restore normal business operations before any analysis has been performed within the affected environment","To notify external regulators and the public about the details of the confirmed incident","To collect and preserve volatile evidence from the affected systems before shutting down"], correct:0, explanation:"Eradication removes the root cause and artifacts; restoration is recovery, notification is communication, and evidence collection is earlier, so those are wrong." },
  { id:81066, domain:5, level:1, question:"Which practice helps prevent SSRF attacks in a cloud-hosted web application?", options:["Returning verbose error messages that reveal the exact internal URLs that were requested within the affected environment","Validating and allow-listing outbound request destinations and blocking metadata endpoints","Allowing the application to fetch any user-supplied URL without any restriction at all","Disabling all outbound network logging so the fetched destinations are never recorded"], correct:1, explanation:"Allow-listing destinations and blocking metadata endpoints prevents SSRF; verbose errors, unrestricted fetches, and no logging increase risk, so those are wrong." },
  { id:81067, domain:5, level:2, question:"Why should organizations regularly test their cloud incident response plan?", options:["Testing guarantees that no incident will ever occur once the plan has been exercised","Testing automatically remediates every vulnerability discovered during the exercise itself","Testing reveals gaps in tooling, access, and procedures before a real incident occurs","Testing removes the need to maintain any logging or monitoring in the environment"], correct:2, explanation:"Testing reveals gaps before real incidents; it does not prevent all incidents, auto-remediate, or remove monitoring, so those options are wrong." },
  { id:81068, domain:5, level:2, question:"Which cloud artifact is most useful for identifying which identity performed a suspicious action?", options:["Aggregate billing charts that show only total monthly spending without any per-action detail","Network throughput graphs that display bandwidth usage without attributing it to any identity","Autoscaling event history that shows only when instances were added or removed from a group","Audit logs that record the caller identity, action, timestamp, and source of each API call"], correct:3, explanation:"Audit logs attribute actions to identities; billing charts, throughput graphs, and autoscaling history lack that attribution, so those are wrong." },
  { id:81069, domain:5, level:2, question:"What is a key consideration when acquiring evidence from a SaaS platform?", options:["The customer usually must request logs and exports through the provider's available interfaces","The customer can always image the underlying physical servers hosting the SaaS application within the affected environment","The provider is legally required to hand over the raw disks of every tenant on request","SaaS platforms never retain any logs that could be useful for a forensic investigation"], correct:0, explanation:"SaaS evidence usually comes via provider interfaces; customers cannot image servers, providers do not hand over disks, and SaaS does keep logs, so those are wrong." },
  { id:81070, domain:5, level:1, question:"Which control most directly mitigates broken authentication on a web login?", options:["Displaying whether the username or the password was incorrect to help users log in faster within the affected environment","Enforcing strong passwords, multi-factor authentication, and secure session management together","Allowing unlimited login attempts so that legitimate users are never locked out of accounts","Storing user passwords using a fast, unsalted hash to speed up the verification process"], correct:1, explanation:"Strong passwords, MFA, and secure sessions mitigate broken authentication; detailed errors, unlimited attempts, and weak hashing worsen it, so those are wrong." },
  { id:81071, domain:5, level:3, question:"Why is it important to identify the initial access vector during incident analysis?", options:["It is only useful for assigning blame and has no bearing on the technical response effort","Identifying the vector automatically restores all affected systems to their prior clean state","Understanding how the attacker got in guides eradication and prevents the same reentry path","The initial vector is irrelevant once the attacker has already been removed from the systems"], correct:2, explanation:"Knowing the vector guides eradication and prevents reentry; it is not just for blame, does not auto-restore, and remains relevant, so those are wrong." },
  { id:81072, domain:5, level:2, question:"Which is a strong indicator of a compromised WordPress or CMS web application?", options:["A steady number of legitimate visitors reading the site's published blog articles each day within the affected environment","Scheduled content being published automatically at the times the editors originally planned","The site's contact form successfully sending messages to the configured administrator inbox","Unexpected new admin users, unfamiliar plugins, and modified core files appearing on the site"], correct:3, explanation:"New rogue admins, unfamiliar plugins, and modified core files indicate compromise; normal visitors, scheduled posts, and working forms are benign, so those are wrong." },
  { id:81073, domain:5, level:3, question:"What is the benefit of using infrastructure-as-code security scanning before deployment?", options:["It catches insecure configurations in templates before they ever reach the running environment","It guarantees that the deployed infrastructure will never be targeted by any attacker at all within the affected environment","It automatically responds to and contains every incident once the infrastructure is deployed","It removes the need to monitor the deployed infrastructure for any runtime security issues"], correct:0, explanation:"Scanning IaC catches insecure configs pre-deployment; it does not prevent all attacks, auto-contain incidents, or remove runtime monitoring, so those are wrong." },
  { id:81074, domain:5, level:2, question:"Which action helps prevent privilege escalation through overly broad cloud roles?", options:["Granting every role administrative access to avoid frequent permission-related support tickets","Regularly reviewing and right-sizing permissions to remove unused and excessive entitlements","Never reviewing permissions once granted so that access remains stable and predictable","Sharing highly privileged roles among many users to simplify overall access management"], correct:1, explanation:"Reviewing and right-sizing permissions prevents escalation; broad admin grants, never reviewing, and sharing privileged roles all increase risk, so those are wrong." },
  { id:81075, domain:5, level:1, question:"Why is DNS logging valuable when investigating cloud-based malware or C2 activity?", options:["It records the full content of every encrypted payload sent between the hosts involved","It automatically blocks any domain that has ever been associated with malicious activity","It can reveal connections to malicious domains used for command and control or exfiltration","It replaces the need to collect any other network or host telemetry during the investigation"], correct:2, explanation:"DNS logs reveal C2 or exfiltration domains; they do not capture encrypted payloads, auto-block, or replace other telemetry, so those are wrong." },
  { id:81076, domain:5, level:3, question:"Which is an appropriate first step upon detecting a suspected web application breach?", options:["Immediately rebuild every server in the environment before confirming whether a breach occurred","Publicly announce a confirmed breach before the incident has been properly validated at all","Delete all of the web server logs to prevent the attacker from covering their own tracks","Verify the alert and assess the scope before taking disruptive containment actions blindly"], correct:3, explanation:"Verifying and scoping first avoids overreaction; blind rebuilds, premature announcements, and deleting logs harm the response, so those are wrong." },
  { id:81077, domain:5, level:2, question:"What is the risk of allowing unrestricted CORS on a sensitive web API?", options:["Malicious origins can read authenticated responses, enabling cross-origin data theft from users","The API will refuse to respond to any request that originates from a different web origin within the affected environment","The API automatically encrypts every response, which slows down legitimate client requests","Unrestricted CORS makes the API immune to any form of cross-site request forgery attack"], correct:0, explanation:"Permissive CORS lets malicious origins read authenticated responses; it does not block cross-origin requests, encrypt, or prevent CSRF, so those are wrong." },
  { id:81078, domain:5, level:3, question:"Which measure best protects cloud workloads from exploitation of known CVEs?", options:["Relying only on network firewalls while never updating the software running on the workloads","Timely vulnerability scanning and patch management across all instances and container images","Assuming cloud workloads are inherently immune to known vulnerabilities the provider has seen","Disabling vulnerability scanning to avoid generating findings that require remediation effort"], correct:1, explanation:"Scanning and patching protects against known CVEs; firewalls alone, assumed immunity, and disabled scanning leave workloads exposed, so those are wrong." },
  { id:81079, domain:5, level:2, question:"Why is it useful to correlate cloud logs with endpoint and network telemetry during an incident?", options:["A single log source is always sufficient and correlation only adds unnecessary complexity","Correlation automatically removes any false positives from every one of the individual sources","Combining sources builds a fuller picture of attacker activity across the entire environment","Correlation replaces the need to preserve any of the underlying evidence for later review"], correct:2, explanation:"Correlating sources builds a fuller picture; a single source is often insufficient, correlation does not auto-remove false positives or replace evidence, so those are wrong." },
  { id:81080, domain:5, level:3, question:"Which is a recommended way to secure webhooks used by a cloud application?", options:["Accept any incoming webhook payload without validation so that no legitimate event is lost","Log webhook payloads only, while processing every request regardless of its authenticity","Expose the webhook endpoint publicly without authentication to simplify integration setup","Verify signatures on incoming webhook payloads and restrict senders to trusted sources"], correct:3, explanation:"Signature verification and sender restriction secure webhooks; accepting anything, log-only processing, and open endpoints are insecure, so those are wrong." },
  { id:81081, domain:5, level:1, question:"What is the primary purpose of tabletop exercises for cloud incident readiness?", options:["To rehearse decision-making and coordination among responders before a real incident happens","To automatically patch every discovered vulnerability across the cloud environment in real time","To replace the technical monitoring and detection tooling deployed within the environment","To guarantee that the organization will never experience a security incident in the future"], correct:0, explanation:"Tabletop exercises rehearse decisions and coordination; they do not patch, replace tooling, or guarantee incident-free operations, so those are wrong." },
  { id:81082, domain:5, level:2, question:"Which behavior suggests an attacker is establishing persistence in a web application?", options:["Reading the site's public homepage a single time from an ordinary residential IP address within the affected environment","Adding a hidden administrative account or scheduled task that survives normal maintenance","Submitting a valid contact form message through the site's standard public web interface","Downloading a publicly available product brochure linked from the site's front page"], correct:1, explanation:"Hidden admin accounts and scheduled tasks establish persistence; reading a page, submitting a form, or downloading a brochure are benign, so those are wrong." },
  { id:81083, domain:5, level:3, question:"Why should sensitive cloud operations require approval workflows or break-glass procedures?", options:["They make every operation slower so that attackers eventually give up and leave the environment","They automatically encrypt all data involved in the operation before it is allowed to proceed","They add oversight so a single compromised identity cannot silently perform destructive actions","They remove the need to log the sensitive operations since approval already implies safety"], correct:2, explanation:"Approval workflows add oversight against a single compromised identity; they do not just slow attackers, encrypt data, or remove logging, so those are wrong." },
  { id:81084, domain:5, level:2, question:"Which is a key sign that a cloud database has been targeted by an injection attack?", options:["A gradual and expected increase in the number of legitimate read queries during business hours","Successful scheduled backups of the database completing at their normal configured times","Routine index maintenance running automatically during the planned low-traffic overnight window","Application logs showing malformed queries and database errors tied to user-supplied input"], correct:3, explanation:"Malformed queries and errors tied to user input signal injection; normal read growth, backups, and index maintenance are benign, so those are wrong." },
  { id:81085, domain:5, level:3, question:"What is the advantage of automated response playbooks in a cloud SOAR platform?", options:["They execute consistent containment steps quickly, reducing response time for known incidents","They eliminate the need for any human analyst involvement in every incident that occurs within the affected environment","They guarantee that no false positives will ever trigger any automated response action","They permanently prevent attackers from ever attempting to compromise the environment"], correct:0, explanation:"Automated playbooks speed consistent containment; they do not remove analysts entirely, eliminate false positives, or prevent attacks, so those are wrong." },
  { id:81086, domain:5, level:1, question:"Which practice reduces the impact of a compromised third-party JavaScript library on a website?", options:["Loading as many external scripts as possible so that no single library becomes critical within the affected environment","Using subresource integrity and content security policy to constrain and verify loaded scripts","Trusting every third-party script by default because reputable vendors are never compromised","Disabling all client-side scripting logging so script errors no longer clutter the console"], correct:1, explanation:"SRI and CSP constrain and verify third-party scripts; loading many scripts, blind trust, and disabling logging increase risk, so those are wrong." },
  { id:81087, domain:5, level:2, question:"Why is it important to define incident severity levels for cloud and web incidents?", options:["They automatically resolve low-severity incidents without any analyst reviewing them at all within the affected environment","They guarantee that high-severity incidents can never actually occur in the environment","They guide prioritization, escalation, and resource allocation appropriate to the incident's impact","They remove the need to document any details about the lower-severity incidents that arise"], correct:2, explanation:"Severity levels guide prioritization and escalation; they do not auto-resolve, prevent incidents, or remove documentation needs, so those are wrong." },
  { id:81088, domain:5, level:2, question:"Which is a strong control against credential stuffing on a web login endpoint?", options:["Allowing unlimited rapid login attempts so that legitimate users never face any friction","Returning a detailed message indicating whether the email address exists in the system","Storing all user passwords in a single reusable format across every application account","Rate limiting, bot detection, and multi-factor authentication applied to the login flow"], correct:3, explanation:"Rate limiting, bot detection, and MFA counter credential stuffing; unlimited attempts, user enumeration, and reused formats worsen it, so those are wrong." },
  { id:81089, domain:5, level:2, question:"What is the role of a jump host or bastion in secure cloud administration?", options:["It provides a controlled, logged entry point for administrative access to private resources","It directly exposes every internal resource to the public internet for easier remote access","It stores all administrative credentials in plaintext for quick retrieval by any operator","It replaces the need for any authentication when connecting to the internal environment"], correct:0, explanation:"A bastion is a controlled, logged access point; it does not expose everything publicly, store plaintext credentials, or remove authentication, so those are wrong." },
  { id:81090, domain:5, level:1, question:"Which factor is most important when prioritizing which cloud incident to handle first?", options:["The alphabetical order of the affected resource names as they appear in the console","The potential business impact and sensitivity of the affected data and systems involved","The personal preference of whichever analyst happens to notice the alert first that day","The age of the cloud account in which the affected resource was originally created"], correct:1, explanation:"Business impact and data sensitivity drive prioritization; alphabetical order, analyst preference, and account age are irrelevant, so those are wrong." },
  { id:81091, domain:5, level:3, question:"Why should a web application enforce output encoding based on the output context?", options:["A single universal encoding is always sufficient for every possible output location on a page within the affected environment","Output encoding is only necessary for data that is never displayed to any end user at all","Different contexts like HTML, attributes, and JavaScript require distinct encoding to stop XSS","Encoding the output automatically validates that the input was free of malicious content"], correct:2, explanation:"Context-specific encoding prevents XSS across contexts; a single encoding is insufficient, encoding applies to displayed data, and it is not input validation, so those are wrong." },
  { id:81092, domain:5, level:2, question:"Which is a benefit of tokenizing sensitive data in a cloud web application?", options:["Tokenization makes the application immune to every category of web application attack at once","Tokenization removes the requirement to authenticate any user accessing the application data","Tokenization automatically scales the application's compute resources during heavy load","Real sensitive values are replaced with non-sensitive tokens, reducing exposure if breached"], correct:3, explanation:"Tokenization reduces exposure by substituting non-sensitive tokens; it does not grant immunity, remove authentication, or scale compute, so those are wrong." },
  { id:81093, domain:5, level:3, question:"What should a handler do after containing a compromised cloud identity?", options:["Investigate the full extent of what the identity accessed and changed during the compromise","Immediately delete every log associated with the identity to simplify the final report within the affected environment","Assume no further action is needed once the identity's password has simply been reset","Restore the identity's original broad permissions to avoid disrupting its automated jobs"], correct:0, explanation:"Investigating the full extent guides remediation; deleting logs, assuming completion, or restoring broad permissions are unsafe, so those are wrong." },
  { id:81094, domain:5, level:2, question:"Which practice best supports rapid detection of misconfigured cloud resources at scale?", options:["A one-time manual audit performed by a single engineer at the start of each fiscal year within the affected environment","Continuous automated configuration assessment against security baselines across all accounts","Waiting for an external penetration test scheduled once every few years to find the issues","Relying on each resource owner to self-report any misconfigurations they happen to notice"], correct:1, explanation:"Continuous automated assessment scales detection; annual manual audits, rare pentests, and self-reporting are too slow or unreliable, so those are wrong." },
  { id:81095, domain:5, level:1, question:"Why is it important to preserve original timestamps when collecting web server logs?", options:["Timestamps are only useful for billing and have no relevance to the forensic investigation within the affected environment","Preserving timestamps automatically encrypts the log entries against any tampering attempt","Accurate timestamps are essential for building a reliable timeline of the attacker's actions","Original timestamps guarantee that the logs will be accepted as evidence in every court"], correct:2, explanation:"Original timestamps build a reliable timeline; they are not just billing data, do not encrypt logs, and do not guarantee court acceptance, so those are wrong." },
  { id:81096, domain:5, level:3, question:"Which is a recommended approach to handling a zero-day exploit against a web application?", options:["Take no action at all because no official vendor patch is currently available for the flaw","Immediately shut down the entire organization's network until a permanent patch is released","Publicly publish the working exploit so that the vendor is pressured to respond faster","Apply virtual patching via WAF rules and compensating controls while awaiting a vendor fix"], correct:3, explanation:"Virtual patching and compensating controls mitigate zero-days; inaction, total shutdown, and publishing the exploit are inappropriate, so those are wrong." },
  { id:81097, domain:5, level:2, question:"What is a primary indicator that a cloud function has been abused by an attacker?", options:["Unexpected invocations, altered code, or outbound connections that deviate from the normal baseline","The function completing its scheduled runs successfully within its normal execution duration within the affected environment","A gradual, expected rise in invocation counts that matches documented growth in legitimate usage","Routine deployment of a new function version through the standard approved CI/CD pipeline"], correct:0, explanation:"Unexpected invocations, altered code, or anomalous outbound connections indicate abuse; normal runs, expected growth, and approved deploys are benign, so those are wrong." },
  { id:81098, domain:5, level:3, question:"Why should organizations retain cloud and web logs for an adequate period?", options:["Longer retention automatically prevents any future attacks against the logged environment within the affected environment","Attacks are often discovered long after they occur, and older logs are needed to investigate them","Retaining logs for a long time makes the environment immune to data exfiltration attempts","Log retention removes the need to apply any access controls to the stored log data itself"], correct:1, explanation:"Adequate retention supports investigating late-discovered attacks; it does not prevent attacks, grant immunity, or remove access controls, so those are wrong." },
  { id:81099, domain:5, level:2, question:"Which is the best way to validate that eradication succeeded before entering recovery?", options:["Assume eradication succeeded because the most obvious malicious file was already deleted earlier","Skip validation entirely so that the business can resume normal operations much faster than usual","Confirm attacker artifacts and access are gone by scanning and comparing against a clean baseline","Ask the attacker directly whether they still retain any access to the compromised environment"], correct:2, explanation:"Scanning and baseline comparison validate eradication; assuming, skipping validation, or asking the attacker are unreliable, so those are wrong." },
  { id:81100, domain:5, level:3, question:"Why is customer-managed encryption key control important during a cloud incident?", options:["It transfers all responsibility for data confidentiality entirely to the cloud provider instead","It guarantees the encrypted data can never be accessed by anyone including the legitimate owner","It removes the need to monitor who is accessing the encrypted data across the environment","It lets the customer revoke or rotate keys to cut attacker access to encrypted data quickly"], correct:3, explanation:"Customer-managed keys allow rapid revocation to cut access; they do not transfer responsibility, block the owner, or remove monitoring, so those are wrong." },
];
